pub const BOOKS: &[Book] = &[
    Book { id: "sundering", title: "THE SUNDERING", cat: "HISTORY", by: "ARCHIVIST VELL", where_: "town", col: 0xc8a060, text: "IN THE FIRST AGE THE WORLD WAS ONE, BOUND AT ITS CORE BY THE WRIFTHEART - A CRYSTAL HEART THAT BEAT BENEATH THE STONE AND HELD ALL LANDS IN ONE EMBRACE.\n\nTHEN CAME THE SUNDERING. THE HEART BROKE INTO TEN SHARDS AND FLUNG THEM TO THE FAR CORNERS. WHERE EACH SHARD FELL, THE LAND TWISTED - MEADOW TO ASH, RIVER TO TAR, FOREST TO HOLLOW.\n\nTHE WORLD WILL NOT BE WHOLE AGAIN UNTIL THE TEN ARE GATHERED AND THE HEART IS MADE TO BEAT ONCE MORE.", teaches: None },
    Book { id: "weepingking", title: "THE WEEPING KING", cat: "LEGEND", by: "UNKNOWN", where_: "castle", col: 0x9a6ad0, text: "THEY CALLED HIM KING AZREL THE BRIGHT, AND HE WAS NOT CONTENT TO RULE ONE WORLD WHEN THE WRIFTHEART HELD THE KEYS TO MANY.\n\nHE STRUCK THE HEART WITH A BLADE OF HIS OWN MAKING, MEANING TO TAKE ITS POWER. INSTEAD IT SHATTERED, AND THE RIFT IT LEFT SWALLOWED HIS CITY WHOLE.\n\nNOW HE SITS IN THE BLACK CASTLE THAT GREW OVER HIS THRONE, WEEPING FOR A CROWN OF DUST, GUARDING THE BROKEN HEART HE CANNOT MEND.", teaches: None },
    Book { id: "blackcastle", title: "ON THE BLACK CASTLE", cat: "HISTORY", by: "ARCHIVIST VELL", where_: "castle", col: 0xc8a060, text: "NO MASON LAID THE BLACK CASTLE. IT ROSE OF ITSELF FROM THE RIFT, STONE PULLED FROM A HUNDRED RUINED PLACES, FUSED BY GRIEF AND DARK INTENT.\n\nITS GROUNDS KNOW NEITHER DAWN NOR DUSK - ONLY A GREY PERPETUAL GLOOM, LIT BY BRAZIERS THAT BURN WITHOUT FUEL.\n\nAT ITS HEART WAITS THE WRIFTHEART, AND THE THING THE KING BECAME. THE GATE OPENS ONLY TO ONE WHO BEARS ALL TEN SHARDS.", teaches: None },
    Book { id: "lastnight", title: "THE LAST NIGHT OF EMBERFALL", cat: "JOURNAL", by: "A SURVIVOR", where_: "emberfall", col: 0x9a6a3a, text: "I WRITE THIS SO SOMEONE REMEMBERS OUR VILLAGE WAS HERE.\n\nTHE SKY TORE OPEN ABOVE THE HILLS AND SOMETHING FELL BURNING. BY MORNING EMBERFALL WAS ASH, THE WELL DRY, THE FIELDS TURNED TO GLASS.\n\nONLY THE ONE FROM THE LAST COTTAGE LIVED, THROWN AWAKE BY THE BOOM. IF YOU READ THIS - GO AND PUT THE WORLD BACK TOGETHER. WE COULD NOT.", teaches: None },
    Book { id: "shardseeker", title: "NOTES OF A SHARD-SEEKER", cat: "JOURNAL", by: "TORWEN THE BOLD", where_: "dungeon", col: 0x9a6a3a, text: "DAY 40. THREE SHARDS TAKEN. EACH GUARDED BY A BEAST THAT IS HALF OF THE LAND IT POISONS.\n\nDAY 71. THE SHARDS ARE COLD AND THEY WHISPER. SOME NIGHTS I HEAR THE KING IN THEM, ASKING ME TO STOP.\n\nDAY ?. I CANNOT LIFT THE FOURTH. MY HANDS SHAKE. WHOEVER FINDS THIS - BE BRAVER THAN TORWEN WAS. I AM GOING HOME.", teaches: None },
    Book { id: "twelverealms", title: "THE TWELVE-AND-MORE REALMS", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "town", col: 0x5a8a4a, text: "A SHARD DOES NOT MERELY REST IN A LAND - IT REMAKES IT. NEAR A SHARD OF FROST, A FOREST BECOMES A WHITE SILENCE. NEAR A SHARD OF FLAME, THE EMBERMAW.\n\nI HAVE WALKED MEADOW, MIRE, AND MUSHROOM WOOD; THE PRISM WASTES WHERE LIGHT BENDS WRONG; THE STARLESS DEEP BELOW.\n\nTHE FARTHER FROM HOME YOU WANDER, THE CRUELER THE GROUND. THIS IS NO ACCIDENT. IT IS DISTANCE FROM THE HEART.", teaches: None },
    Book { id: "starlessdeep", title: "THE STARLESS DEEP", cat: "LEGEND", by: "UNKNOWN", where_: "dungeon", col: 0x9a6ad0, text: "BENEATH THE WORLD'S SKIN LIE CAVERNS THAT NEVER KNEW THE SUN - THE BLACKDEEP, WHERE CRYSTAL GROWS LIKE WEEDS AND THE DARK HAS WEIGHT.\n\nTHE DEEP-FOLK, IF THEY EVER WERE, LEFT ONLY GLYPHS THAT GLOW WHEN YOU LOOK AWAY.\n\nCARRY A LANTERN. THE DEEP DOES NOT HATE YOU. IT SIMPLY DOES NOT KNOW YOU ARE THERE, AND THAT IS WORSE.", teaches: None },
    Book { id: "ogres", title: "OF OGRES AND THEIR KIND", cat: "FIELD NOTES", by: "HUNTSMAN GRELL", where_: "camp", col: 0x5a8a4a, text: "THE OGRE IS A HILL THAT LEARNED TO HOLD A CLUB. DO NOT MISTAKE ITS SLOWNESS FOR SAFETY - IT WINDS UP LIKE A STORM AND CHARGES.\n\nSTRIKE WHEN THE SWING HAS PASSED, NOT BEFORE. ITS HIDE TURNS LESSER BLADES.\n\nTHEY WERE GENTLE ONCE, THE OLD HUNTERS SAY, BEFORE A SHARD SOURED THE HIGH VALLEYS. NOW THEY ONLY REMEMBER THE ANGER.", teaches: None },
    Book { id: "baldhero", title: "THE BALLAD OF THE BALD HERO", cat: "FOLK TALE", by: "A TAVERN SONG", where_: "town", col: 0xd27a9a, text: "OH THE HERO CAME WITH A SHINING PATE, NO HELM COULD SIT NOR HAIR COULD GROW, AND THE FOLK ALL LAUGHED AT THE BALD ONE'S FATE - TILL THE BALD ONE LAID THE DARK LOW!\n\nSO RAISE A CUP TO THE GLEAMING HEAD, FOR COURAGE WEARS NO CROWN OF HAIR; THE PROUD KINGS FELL AND THE PROUD KINGS BLED, BUT THE BALD ONE? THE BALD ONE WAS THERE.", teaches: None },
    Book { id: "litany", title: "THE LITANY OF THE RIFT", cat: "SCRIPTURE", by: "THE SHARDED CHOIR", where_: "dungeon", col: 0xc4c4d4, text: "BLESSED IS THE BREAK, FOR FROM BREAKING COMES THE MANY. BLESSED IS THE SHARD, THAT WE MAY EACH HOLD A PIECE OF GOD.\n\nDO NOT MEND THE HEART, PILGRIM. A WHOLE HEART BEATS FOR ALL AND SO FOR NONE.\n\nLET IT STAY BROKEN. LET US KEEP OUR PIECES. THIS IS THE LITANY; THIS IS THE RIFT.", teaches: None },
    Book { id: "almanac", title: "A FARMER'S ALMANAC", cat: "ALMANAC", by: "GOODWIFE BREN", where_: "town", col: 0xcaa84a, text: "THE YEAR TURNS IN FOUR: SPRING TO PLANT, SUMMER TO TEND, FALL TO REAP, WINTER TO REST.\n\nA CROP DRINKS ONCE A DAY OR IT WITHERS. WHEN THE SKY OPENS AND RAIN COMES, IT WATERS YOUR ROWS FOR FREE - SO PRAY FOR GREY MORNINGS.\n\nPLANT NOTHING OUT OF ITS SEASON. THE LAND REMEMBERS WHAT BELONGS, EVEN IF WE FORGET.", teaches: None },
    Book { id: "skyweeps", title: "WHY THE SKY WEEPS", cat: "FOLK TALE", by: "A NURSE'S RHYME", where_: "town", col: 0xd27a9a, text: "WHEN THE HEART BROKE, THE SKY BROKE TOO, AND IT HAS NEVER STOPPED GRIEVING.\n\nON GREY DAYS THE SKY IS ONLY SAD AND WEEPS ITS RAIN. ON BLACK DAYS IT IS ANGRY, AND FLINGS DOWN FIRE AND DRUM.\n\nIN THE COLD NORTH ITS TEARS FREEZE BEFORE THEY FALL, AND THAT IS SNOW. HUSH NOW. THE SKY WILL DRY ITS EYES WHEN THE HERO COMES.", teaches: None },
    Book { id: "waters", title: "WATERS AND WHAT SWIMS THEM", cat: "FIELD NOTES", by: "OLD ANGLER PORK", where_: "camp", col: 0x5a8a4a, text: "CLEAR BLUE WATER AND BLACK SWAMP MURK ARE NOT THE SAME POND, AND THEY DO NOT HOLD THE SAME FISH.\n\nTHE RARE ONES BITE IN STRANGE WEATHER. I HOOKED A RAINFISH ONLY IN A DOWNPOUR, AND A THING OF VIOLET FINS ONLY UNDER THUNDER.\n\nPATIENCE IS THE WHOLE OF THE CRAFT. WAIT FOR THE LINE TO DIP - THEN, AND ONLY THEN, PULL.", teaches: None },
    Book { id: "smithledger", title: "A SMITH'S LEDGER", cat: "FIELD NOTES", by: "FORGE-HAND DUN", where_: "town", col: 0x5a8a4a, text: "COPPER FOR THE FIRST BLADE. THEN IRON, THEN SILVER, THEN GOLD, THEN THE MITHRIL THAT SINGS WHEN STRUCK.\n\nYOU CANNOT MINE WHAT YOUR PICK IS TOO SOFT TO BITE. EARN THE BETTER TOOL BEFORE YOU CURSE THE STUBBORN STONE.\n\nA GOOD TABLE IS WORTH MORE THAN A GOOD SWORD. PLACE YOUR FORGE; THE REST FOLLOWS.", teaches: None },
    Book { id: "foundingtowns", title: "THE FOUNDING OF THE TOWNS", cat: "HISTORY", by: "ARCHIVIST VELL", where_: "town", col: 0xc8a060, text: "AFTER THE SUNDERING THE SCATTERED FOLK GATHERED WHERE THE GROUND STILL HELD - A WELL, A WALL, A REASON TO STAY.\n\nTHEY TRADED WHAT THEY HAD AND GUARDED WHAT THEY COULD, AND CALLED IT A TOWN, AND CALLED IT ENOUGH.\n\nEVERY TOWN IS A SMALL DEFIANCE OF THE RIFT. EVERY LIT WINDOW SAYS: NOT YET. NOT US. NOT TONIGHT.", teaches: None },
    Book { id: "witherwhisper", title: "WHISPERS FROM THE WITHER", cat: "SCRIPTURE", by: "NAILED TO A DEAD TREE", where_: "dungeon", col: 0xc4c4d4, text: "THE WITHERLANDS ARE WHERE A SHARD LAY LONGEST UNTAKEN, AND ROT LEARNED TO THINK.\n\nDO NOT EAT WHAT GROWS THERE. DO NOT DRINK. DO NOT SLEEP WHERE THE GREY MOSS CAN REACH YOU, FOR IT DREAMS, AND IT WOULD LIKE TO DREAM AS YOU.\n\nI HAVE SAID TOO MUCH. THE WHISPERING IS LOUDER WHEN YOU LISTEN. STOP LISTENING. STOP REA", teaches: None },
    Book { id: "firstwand", title: "THE FIRST WAND", cat: "LEGEND", by: "THE GREY COLLEGE", where_: "town", col: 0x9a6ad0, text: "MAGIC IS NOT A GIFT. IT IS A LEAK. WHERE THE WRIFTHEART CRACKED THE WORLD, POWER SEEPS THROUGH, AND A WAND IS ONLY A STRAW TO SIP IT.\n\nTHE FIRST MAGE CARVED HER WAND FROM A BRANCH STRUCK BY A FALLING SHARD. IT NEVER STOPPED HUMMING.\n\nSOCKET A RUNE AND THE WAND REMEMBERS A SPELL. BUT TAKE CARE - WHAT LEAKS IN CAN ALSO LEAK OUT OF YOU.", teaches: None },
    Book { id: "graveward", title: "THE GRAVEWARD RITES", cat: "SCRIPTURE", by: "THE LANTERN ORDER", where_: "dungeon", col: 0xc4c4d4, text: "WE DO NOT BURY THE DEAD TO HIDE THEM. WE BURY THEM TO KEEP THEM STILL.\n\nSINCE THE GRAVEBLOOM SHARD FELL AMONG THE TOMBS, THE STILLNESS HAS FAILED. THEY RISE, NOT HUNGRY, ONLY RESTLESS - DENIED THE SLEEP THE SHARD WON'T GRANT.\n\nLIGHT A LANTERN AT EVERY GRAVE. IT WILL NOT STOP THEM. BUT IT TELLS THEM SOMEONE STILL REMEMBERS THEIR NAMES.", teaches: None },
    Book { id: "herbal", title: "THE WANDERING HERBAL", cat: "ALMANAC", by: "APOTHECARY SAGE", where_: "town", col: 0xcaa84a, text: "A RED HERB STEEPED IS A POTION; DRINK IT AND A WOUND CLOSES. THIS IS THE WHOLE OF THE ART, AND ITS HARDEST LESSON.\n\nFOOD IS NOT MEDICINE. A HEARTY MEAL STEADIES THE HAND AND QUICKENS THE STEP FOR A WHILE, BUT IT WILL NOT KNIT YOUR SKIN. KNOW THE DIFFERENCE BEFORE YOU NEED IT.\n\nGATHER IN SEASON. THE RAREST LEAVES GROW ONLY WHERE THE SHARDS HAVE MADE THE GROUND STRANGE.", teaches: None },
    Book { id: "minerssong", title: "THE MINER'S SONG", cat: "FOLK TALE", by: "SUNG UNDERGROUND", where_: "camp", col: 0xd27a9a, text: "COPPER FOR A PENNY, IRON FOR A POUND, SILVER FOR A SECRET, GOLD TO GO AROUND - BUT MITHRIL, OH MY MITHRIL, SINGS BENEATH THE GROUND!\n\nSWING LOW, SWING SLOW, AND MIND THE DARK BELOW; THE DEEPER THAT YOU DIG, THE RICHER THAT YOU GROW. BUT THE STARLESS DEEP IS LISTENING - SO MIND THE DARK BELOW.", teaches: None },
    Book { id: "tradersroad", title: "THE TRADER S ROAD", cat: "JOURNAL", by: "PEDDLER COSS", where_: "town", col: 0x9a6a3a, text: "EVERY TOWN BUYS AND EVERY TOWN SELLS, BUT NO TWO AT THE SAME PRICE. A SHARP EYE EARNS MORE THAN A SHARP SWORD.\n\nTHE BLACKSMITH WANTS ORE, THE SCHOLAR WANTS RUMOUR, THE INN WANTS A SONG. CARRY A LITTLE OF EACH AND YOU NEED NEVER GO HUNGRY.\n\nI HAVE SOLD A BENT NAIL FOR A GOLD COIN BY CALLING IT A RELIC. FORGIVE ME. THE ROAD IS LONG.", teaches: None },
    Book { id: "beastfolio", title: "THE CORRUPTED FOLIO", cat: "FIELD NOTES", by: "WARDEN ILSE", where_: "dungeon", col: 0x5a8a4a, text: "EVERY BEAST NEAR A SHARD WEARS A SECOND SHADOW. THESE ARE THE CORRUPTED - LARGER, ANGRIER, AND LIT FROM WITHIN BY A LIGHT THAT IS NOT HEALTHY.\n\nAN ELITE LEADS; A CHAMPION RULES. KILL THE CROWNED ONE AND ITS PACK LOSES HEART.\n\nTHEY ARE NOT EVIL. THEY ARE WOUNDED, THE SAME AS THE LAND. BUT A WOUNDED THING STILL BITES.", teaches: None },
    Book { id: "inland", title: "THE INLAND SEA", cat: "FIELD NOTES", by: "CAPTAIN MAREE", where_: "camp", col: 0x5a8a4a, text: "THE SUNCOAST WAS NOT ALWAYS A COAST. BEFORE THE SUNSTONE FELL AND DRANK THE RIVERS, SHIPS SAILED WHERE NOW THERE IS ONLY GLITTERING SALT.\n\nWHAT WATER REMAINS IS WARM AND BRIGHT AND FULL OF STRANGE FISH. CAST A LINE AT NOON IN HIGH SUMMER AND SEE.\n\nTHE OLD HARBOUR BELLS STILL RING WHEN THE WIND IS RIGHT. NO ONE PULLS THE ROPES.", teaches: None },
    Book { id: "chronline", title: "CHRONICLES: THE BRIGHT LINE", cat: "HISTORY", by: "ARCHIVIST VELL", where_: "town", col: 0xc8a060, text: "NINE GENERATIONS THE BRIGHT LINE RULED FROM COR ALDANE, THE WHITE CITY, AND HISTORY RECORDS NO BETTER KINGS AND NO WORSE ENDING.\n\nAZREL, LAST OF THE LINE, WAS CROWNED YOUNG AND RULED WELL. HE LAID THE GREAT ROADS. HE CHARTERED THE GREY COLLEGE. HE MARRIED MAREN OF THE BLUEBELL DOWNS, WHO KEPT BEES AND WAS LOVED BY EVERYONE, WHICH HISTORY RECORDS OF ALMOST NO ONE.\n\nIN THE THIRD YEAR BEFORE THE SUNDERING THE QUEEN DIED OF THE PALE FEVER. THE RECORDS AFTER THIS GROW THIN. THE KING WITHDREW FROM COURT AND TURNED TO HIS STUDIES.\n\nHISTORIANS DISAGREE ON WHAT HE STUDIED. THIS ARCHIVIST NOTES ONLY THAT THE COURT MAGE SORREL ATTENDED HIM DAILY, AND THAT NO GOOD CAME OF IT.\n\nSONGS SAY THE KING WAS MAD WITH GRIEF. SONGS ARE NOT SOURCES. BUT I HAVE READ THE HOUSEHOLD LEDGERS OF THOSE YEARS, AND THE CANDLES ORDERED FOR THE KINGS STUDY WOULD HAVE LIT A VILLAGE.", teaches: None },
    Book { id: "chronblade", title: "CHRONICLES: THE KINGSPLITTER", cat: "HISTORY", by: "ARCHIVIST VELL", where_: "town", col: 0xc8a060, text: "OF THE BLADE ITSELF THE RECORD IS SHORT AND STRANGE. IN THE LAST YEAR OF THE WHOLE AGE THE ROYAL SMITH REFUSED A COMMISSION FROM HIS OWN KING - THE ONLY SUCH REFUSAL IN NINE GENERATIONS - AND WAS NOT PUNISHED FOR IT.\n\nSO THE KING FORGED IT HIMSELF, ALONE, IN THE COLD FORGE UNDER THE EAST TOWER. THE FOLK CALLED IT THE KINGSPLITTER AFTER, THOUGH IT SPLIT NO KING. IT SPLIT EVERYTHING ELSE.\n\nWHAT BECAME OF IT? HERE THE TRAIL RUNS PAST HISTORY INTO RUMOUR. THE BLADE WAS CARRIED FROM THE DROWNING CITY - BY WHOM, NO TWO ACCOUNTS AGREE.\n\nBUT IN THE THIRD CENTURY AFTER, THE BLADE REAPPEARS IN THE WRITINGS OF THE SHARDED CHOIR, WHO NAME IT THE FIRST BELL AND COUNT IT HOLIEST OF ALL THINGS. WHAT THE SINGERS TOOK UP THEY DID NOT PUT DOWN.\n\nNO SCHOLAR HAS FOUND THEIR SANCTUM. THIS ARCHIVIST HAS STOPPED LOOKING, AND ADVISES THE READER TO STOP TOO. SOME DOORS ARE SHUT FROM THE FAR SIDE.", teaches: None },
    Book { id: "chronremains", title: "CHRONICLES: WHAT REMAINS", cat: "HISTORY", by: "ARCHIVIST VELL", where_: "town", col: 0xc8a060, text: "THE FIRST FIFTY YEARS AFTER THE SUNDERING ARE CALLED THE SCATTERING, AND THE NAME IS KIND. THE ROADS BROKE. THE SEASONS RAGED. THE FAR LANDS TWISTED, AND WHAT LIVED THERE TWISTED WITH THEM.\n\nTHE FOLK GATHERED WHERE THE GROUND STILL HELD. THEY RAISED WALLS, DUG WELLS, AND CALLED THE RESULT TOWNS. EVERY TOWN CHARTER FROM THOSE YEARS ENDS WITH THE SAME THREE WORDS: NOT US. NOT TONIGHT.\n\nOF THE WHITE CITY NOTHING REMAINS ABOVE GROUND. IN ITS PLACE STANDS THE BLACK CASTLE, WHICH NO MASON BUILT AND NO ARMY HAS ENTERED. ITS GATE IS SEALED WITH TEN LOCKS, IF THE OLD SURVEYS ARE RIGHT, AND THE TEN KEYS ARE SUNK IN TEN LANDS.\n\nI AM ASKED, AS THE ARCHIVIST, WHAT HISTORY TEACHES. IT TEACHES THIS: THE WORLD DID NOT END. IT BROKE, WHICH IS DIFFERENT. WHAT BREAKS CAN BE GATHERED.\n\nHISTORY IS NOT THE ACCOUNT OF WHAT BROKE. HISTORY IS THE ACCOUNT OF WHO SWEPT UP.", teaches: None },
    Book { id: "letterqueen", title: "A LETTER TO THE QUEEN", cat: "LETTER", by: "KING AZREL", where_: "dungeon", col: 0xe0d6b0, text: "MAREN - THE PROGRESS CRAWLS. FOUR MORE TOWNS, FOUR MORE FEASTS, FORTY MORE SPEECHES. I AM ASSURED THIS IS KINGSHIP. I BEGIN TO SUSPECT KINGSHIP IS SITTING STILL WHILE OTHERS EAT.\n\nTHE STORMCROWN PASSES WERE WHITE AND QUIET AND I THOUGHT OF NOTHING BUT YOUR GARDEN. TELL THE BEES I ASK AFTER THEM. TELL THE BLUEBELLS NOTHING, THEY ARE VAIN ENOUGH.\n\nTHE COLLEGE MEN SHOWED ME A WONDER LAST NIGHT - A WAND THAT SIPS THE WORLDS OWN HUMMING. SORREL SAYS THERE IS MORE BENEATH THE WORLD THAN ANY OF US GUESS. HE SAYS IT THE WAY HE SAYS EVERYTHING, AS IF HE HAS ALREADY BEEN PROVED RIGHT.\n\nTEN DAYS, LOVE. KEEP THE GARDEN. I AM ALWAYS COMING HOME TO IT.\n\n- A.", teaches: None },
    Book { id: "lettermaid", title: "THE CHAMBERMAIDS LETTER", cat: "LETTER", by: "TILLY, OF THE ROYAL HOUSEHOLD", where_: "dungeon", col: 0xe0d6b0, text: "DEAR SIS - YOU ASK HOW THE KING FARES AND I WILL TELL YOU BECAUSE YOU CAN KEEP A SHUT MOUTH.\n\nHE DOES NOT SLEEP. HE WALKS THE QUEENS GARDEN AFTER MIDNIGHT, EVERY MIDNIGHT, RAIN OR NO. HE TALKS LOW TO THE FLOWERS AS IF THEY COULD CARRY WORD TO HER. IT WOULD BREAK YOUR HEART TO HEAR IT. IT BREAKS MINE AND I ONLY SWEEP THE PATHS.\n\nTHE MAGE IS ALWAYS WITH HIM NOW. I DO NOT LIKE TO WRITE ILL OF MY BETTERS BUT THERE IS A WAY A MAN FEEDS A FIRE, SIS, AND THAT IS HOW SORREL TALKS TO THE KING.\n\nLAST NIGHT I HEARD THE KING LAUGH FOR THE FIRST TIME SINCE THE QUEEN WENT. IT SHOULD HAVE GLADDENED ME. IT DID NOT. IT WAS THE LAUGH OF A MAN WHO HAS DECIDED SOMETHING.\n\nBURN THIS LETTER. - T.", teaches: None },
    Book { id: "lettersorrel", title: "SORREL TO THE KING", cat: "LETTER", by: "SORREL, COURT MAGE", where_: "castle", col: 0xe0d6b0, text: "MAJESTY - YOU ASK ME PLAINLY, SO I ANSWER PLAINLY, AND BEG YOU BURN THIS AFTER.\n\nTHE COLLEGE TEACHES THAT THE WRIFTHEART IS A HEART. THE COLLEGE TEACHES WHAT IS SAFE TO TEACH. CONSIDER, MAJESTY: A HEART BEATS AGAINST SOMETHING. A DRUM SOUNDS ONLY WHERE THERE IS A SKIN BETWEEN TWO AIRS.\n\nTHE OLD TEXTS DO NOT CALL IT A HEART. THEY CALL IT THE HINGE. WHAT HAS A HINGE, MAJESTY? NOT A HEART. A DOOR.\n\nAND IF IT IS A DOOR, THEN ITS BEATING IS A KNOCKING. AND IF IT IS A KNOCKING, THEN SOMEONE KNOCKS. I DO NOT SAY SHE WAITS ON THE FAR SIDE. I SAY NO MAN HAS PROVED SHE DOES NOT.\n\nYOU HAVE THE STRENGTH NO SCHOLAR HAS. YOU COULD SIMPLY ASK THE DOOR TO OPEN. AND IF IT WILL NOT HEAR YOU - WELL. YOU ARE A KING. KINGS DO NOT KNOCK TWICE.\n\nYOUR SERVANT IN ALL THINGS - S.", teaches: None },
    Book { id: "lettersmith", title: "THE SMITHS REFUSAL", cat: "LETTER", by: "MASTER SMITH HODDA", where_: "dungeon", col: 0xe0d6b0, text: "TO HIS RADIANT MAJESTY, FROM HIS SMITH, WHO HAS SERVED THE FORGE OF COR ALDANE THIRTY YEARS AND NEVER ONCE SAID NO.\n\nNO.\n\nI HAVE READ THE DRAWINGS. I HAVE READ THEM FOUR TIMES, AND FOUR TIMES MY HANDS HAVE GONE COLD. AN EDGE IS AN HONEST THING, MAJESTY. IT PARTS WOOD FOR THE FIRE AND BREAD FOR THE TABLE AND, WHEN IT MUST, A FOE FROM HIS MISCHIEF. WHAT YOU HAVE DRAWN IS NOT AN EDGE. IT IS AN ARGUMENT WITH THE WORLD.\n\nFORGE IT YOURSELF IF YOU MUST. THE COLD FORGE UNDER THE EAST TOWER STANDS EMPTY, AND YOU WERE NOT A BAD PRENTICE, FOR A PRINCE.\n\nBUT NOT WITH MY HANDS, MAJESTY. THESE HANDS HAVE ONLY EVER MADE THINGS THAT HOLD TOGETHER.", teaches: None },
    Book { id: "lettermaren", title: "THE QUEENS LAST NOTE", cat: "LETTER", by: "QUEEN MAREN", where_: "castle", col: 0xe0d6b0, text: "LOVE - THE FEVER IS PATIENT AND I AM NOT, SO I WRITE WHILE MY HAND IS MINE.\n\nDO NOT FOLLOW ME. I KNOW YOU. I KNOW THE SHAPE YOUR GRIEF WILL TRY TO TAKE - SOMETHING GRAND AND TERRIBLE AND ALL FOR ME. LOVE, I NEVER ONCE WANTED GRAND. I WANTED THE GARDEN, AND YOUR AWFUL SINGING, AND THE BEES.\n\nTEND THE GARDEN. THAT IS ALL I ASK. THINGS GROW, AND THE GROWING IS THE ANSWER, THOUGH I CANNOT NOW REMEMBER TO WHAT QUESTION.\n\nPROMISE ME THE GARDEN. NOT THE DOOR, AZREL. WHATEVER HE TELLS YOU. THE GARDEN.\n\n- M.", teaches: None },
    Book { id: "lettergate", title: "THE GATEWARDENS ACCOUNT", cat: "LETTER", by: "WARDEN OF THE HEART-GATE", where_: "castle", col: 0xe0d6b0, text: "THEY WILL ASK, AFTER. THEY WILL ASK WHO LET HIM PASS, AND THE ANSWER IS ME, AND I WRITE THIS SO THE ASKING FINDS THE TRUTH INSTEAD OF SOMEONE TO HANG.\n\nHE CAME ALONE, PAST MIDNIGHT, IN A PLAIN CLOAK. HE CARRIED SOMETHING LONG, WRAPPED IN THE QUEENS GARDEN-CLOTH. I KNEW THE CLOTH. WE ALL KNEW THE CLOTH.\n\nI ASKED HIM, MAJESTY, WILL YOU HAVE AN ESCORT. HE SAID, NO, SON, I AM ONLY GOING TO KNOCK. AND HE SMILED, AND HE WAS CRYING, AND I STOOD ASIDE.\n\nHE WAS THE KING. WE LET HIM PASS. WE ALWAYS LET HIM PASS - THAT IS WHAT A KING IS.\n\nI FELT THE FIRST CRACK THROUGH MY BOOTS. THE REST YOU KNOW. THE REST EVERYONE KNOWS, FOREVER.", teaches: None },
    Book { id: "torwenoath", title: "TORWENS JOURNAL: THE OATH", cat: "JOURNAL", by: "TORWEN THE BOLD", where_: "dungeon", col: 0x9a6a3a, text: "DAY ONE. THE WORLD IS BROKEN. THIS IS GENERALLY AGREED. SOMEBODY MUST UN-BREAK IT, AND THE SOMEBODIES OF THE LAST HUNDRED YEARS HAVE ALL STAYED HOME, SO IT FALLS TO ME.\n\nINVENTORY: ONE SWORD (GOOD). ONE ROPE (LONG). ONE MAP (WRONG, I SUSPECT). MY MOTHERS DOUBTS (HEAVY, BUT THEY PACK FLAT).\n\nTHE PLAN IS SIMPLE. TEN SHARDS, TEN LANDS. I WILL TAKE THEM ONE AT A TIME, THE WAY YOU EAT ANYTHING TOO BIG.\n\nI HAVE SWORN THE OATH AT THE TOWN WELL, LOUDLY, SO THAT BACKING OUT WILL EMBARRASS ME. THIS IS THE SOUNDEST STRATEGY I KNOW.\n\nDAY TWO. RAIN. HEROISM POSTPONED.", teaches: None },
    Book { id: "torwenfirst", title: "TORWENS JOURNAL: THE FIRST SHARD", cat: "JOURNAL", by: "TORWEN THE BOLD", where_: "dungeon", col: 0x9a6a3a, text: "DAY THIRTY-ONE. I HAVE IT. I HAVE IT! THE BEAST IS DEAD AND THE VERDANT TEAR IS IN MY PACK AND I AM WRITING THIS WITH HANDS THAT WILL NOT STOP SHAKING, FROM JOY OR FROM THE OTHER THING.\n\nLET THE RECORD SHOW THE GUARDIAN WAS THE SIZE OF A BARN. LET THE RECORD SHOW I DID NOT RUN. LET THE RECORD OMIT THE FIRST FIVE MINUTES.\n\nTHE SHARD IS BEAUTIFUL. IT IS ALSO COLD, WHICH THE SONGS DO NOT MENTION, AND IT HUMS, WHICH THEY ALSO DO NOT.\n\nDAY THIRTY-FOUR. THE HUM HAS WORDS IN IT. NOT WORDS. ALMOST-WORDS. LIKE A VOICE THROUGH A WALL.\n\nDAY THIRTY-SIX. LAST NIGHT I DREAMED OF A GARDEN I HAVE NEVER SEEN, AND WEPT IN THE DREAM, AND THE GRIEF WAS NOT MINE. I HAVE WRAPPED THE SHARD IN WOOL. IT DOES NOT HELP.", teaches: None },
    Book { id: "torwensalt", title: "TORWENS JOURNAL: THE SALT", cat: "JOURNAL", by: "TORWEN THE BOLD", where_: "dungeon", col: 0x9a6a3a, text: "DAY NINETY. RUMOUR IN THE LAST TOWN: THE GREY PILGRIMS - THE SHARDED CHOIR, THEY NAME THEMSELVES - KEEP A SANCTUM SOMEWHERE NO ARMY COULD FIND. THE TAVERN-KEEP LEANED CLOSE AND SAID: THE SINGERS ARE BENEATH THE SALT.\n\nDAY NINETY-FOUR. THE SALTWASTES. WHITE AS THE ARCTIC AND TWICE AS THIRSTY. WIND LIKE A FILE ON THE TEETH.\n\nDAY NINETY-FIVE. I FOUND IT. OR THE MOUTH OF IT. A CRACK IN THE SALT-CRUST, AND FROM IT, FAINT AS A PULSE - SINGING. MANY VOICES, VERY DEEP, VERY GLAD. GLAD IS THE WRONG SOUND FOR UNDER THE EARTH.\n\nTHEY KEEP THE KINGS BLADE DOWN THERE. I AM SURE OF IT NOW. I HEARD IT IN THEIR SINGING - THE BELL, THE BELL, THE FIRST AND HOLY BELL.\n\nDAY NINETY-SIX. I DID NOT GO DOWN. WRITE IT PLAIN, TORWEN: YOU STOOD AT THE CRACK AND YOUR COURAGE WOULD NOT COME, AND YOU WALKED AWAY. LET THEM KEEP IT. A SWORD THAT KILLED THE WORLD ONCE DOES NOT WANT A SECOND CHANCE.", teaches: None },
    Book { id: "torwenlast", title: "TORWENS LAST PAGE", cat: "JOURNAL", by: "TORWEN, ONCE CALLED BOLD", where_: "dungeon", col: 0x9a6a3a, text: "THEY TELL ME I AM DYING, WHICH IS TRUE, AND THAT I SHOULD SET DOWN MY GREAT DEEDS, WHICH ARE THREE. I TOOK THREE SHARDS OF TEN. I HAVE HEARD THE SONGS ABOUT ME. THE SONGS ARE KIND AND WRONG.\n\nI DID NOT FAIL AT THE FOURTH BECAUSE THE BEAST WAS TOO STRONG. I FAILED BECAUSE THE SHARDS WHISPER, AND I HAD LISTENED THREE SHARDS TOO LONG. SOME NIGHTS IT WAS THE KING, ASKING ME SOFT TO STOP. SOME NIGHTS IT WAS ME ASKING.\n\nSO I WENT HOME. I MARRIED. I PLANTED TURNIPS. THEY COME UP EVERY YEAR, WHICH IS MORE THAN I CAN SAY FOR HEROES. THAT IS MY MENDING OF THE WORLD, AND I HAVE MADE MY PEACE WITH ITS SIZE.\n\nONE THING MORE, FOR HONESTY. THE THREE SHARDS I TOOK WERE TAKEN FROM MY HOUSE, IN THE NIGHT, IN MY FORTIETH YEAR. NO LOCK WAS BROKEN. I DID NOT LOOK FOR THEM. YOU MAY JUDGE ME FOR THAT. I SLEPT BETTER FROM THAT NIGHT ON.\n\nWHOEVER YOU ARE, READING THIS - AND THE SHARDS WILL SEE TO IT THAT SOMEBODY DOES - BE BRAVER THAN TORWEN. AND WHEN YOU CANNOT BE, BE KINDER TO YOURSELF THAN I WAS. THE WORLD WAS BROKEN BY A MAN WHO COULD NOT FORGIVE HIMSELF. IT WILL NOT BE MENDED BY ANOTHER.", teaches: None },
    Book { id: "emberslate", title: "A SCHOOL SLATE", cat: "RECORD", by: "UNKNOWN", where_: "emberfall", col: 0x8fa08f, text: "(A CHILDS SCHOOL SLATE, SCORCHED ALONG ONE EDGE. THE CHALK HAS BAKED INTO THE STONE AND WILL NOT RUB OUT.)\n\nROLL OF THE EMBERFALL SCHOOL, SPRING TERM: WILLA. TAM. BRICK. SORA. LITTLE HODD. THE MILLERS TWINS.\n\nBENEATH THE ROLL, A LESSON. THE LETTER B, PRACTISED SEVEN TIMES, EACH BETTER THAN THE LAST.\n\nTHE EIGHTH IS ONLY BEGUN.", teaches: None },
    Book { id: "embermiller", title: "THE MILLERS UNSENT LETTER", cat: "LETTER", by: "THE MILLER OF EMBERFALL", where_: "emberfall", col: 0xe0d6b0, text: "BROTHER - THE HARVEST IS IN AND IT IS A GOOD ONE, SO OF COURSE I HAVE FOUND SOMETHING TO WORRY AT. YOU KNOW ME.\n\nPILGRIMS HAVE CAMPED ON THE HILL ABOVE THE VILLAGE SINCE LAST MARKET-DAY. GREY ROBES, VERY POLITE, BUY THEIR BREAD AND PAY FAIR. THE CHILDREN LIKE THEM. THE DOGS DO NOT.\n\nIT IS THE SINGING, BROTHER. THEY SING AT ODD HOURS, AND NOT TO EACH OTHER. THEY STAND ON THE HILLTOP IN A RING AND SING STRAIGHT UP, AS IF THE SKY OWED THEM A DEBT AND THEY HAD COME TO COLLECT.\n\nLAST NIGHT THE SKY OVER THE HILL LOOKED BRUISED. LIKELY WEATHER. THE ALMANAC SAYS GREY MORNINGS ARE A BLESSING.\n\nI WILL FINISH THIS AFTER THE FESTIVAL. THE WHOLE VILLAGE TURNS OUT TONIGHT, AND WILLA HAS PROMISED THE TWINS A BONFIRE.\n\n(THE LETTER ENDS HERE. IT WAS NEVER SENT.)", teaches: None },
    Book { id: "emberroll", title: "THE LANTERN ROLL OF EMBERFALL", cat: "RECORD", by: "THE LANTERN ORDER", where_: "emberfall", col: 0x8fa08f, text: "RECORD OF THE ORDER, YEAR 312 AFTER: BEING THE ROLL OF EMBERFALL, WHICH BURNED IN A NIGHT, FROM A CLEAR SKY, IN NO WAR.\n\nWE CAME AT DAWN AND DID WHAT WE DO. WE DUG, WE SPOKE THE NAMES, WE LIT THE LANTERNS. THE GROUND WAS STILL WARM. THE WELL WAS DRY. THE FIELDS HAD RUN TO GLASS, WHICH NO HONEST FIRE DOES - LET THE RECORD SAY SO, THOUGH THE RECORD CANNOT SAY WHY.\n\nFORTY-ONE GRAVES. THE NAMES ARE KEPT IN THE ORDERS BOOK AND SPOKEN EACH WINTER, AS ALL OUR NAMES ARE. THEY ARE NOT LOST. NO ONE THE ORDER BURIES IS LOST.\n\nONE GRAVE MORE WAS DUG AND STANDS EMPTY. THE ONE FROM THE LAST COTTAGE WAS NOT FOUND - NOT THAT NIGHT, NOT SINCE. THE ORDER DOES NOT FILL A GRAVE ON HOPE.\n\nTHE EMPTY GRAVE IS TENDED. ITS LANTERN IS KEPT LIT. WHEREVER THEY WENT, SOMETHING OF HOME BURNS FOR THEM YET.", teaches: None },
    Book { id: "choirsinger", title: "THE FIRST SINGERS CANTICLE", cat: "SCRIPTURE", by: "THE SHARDED CHOIR", where_: "dungeon", col: 0xc4c4d4, text: "SING OF THE FIRST SINGER, WHO SERVED A GRIEVING KING. SING OF THE WISDOM WHISPERED: THAT A HEART IS ALSO A DOOR.\n\nTHE COLLEGE CALLED HIM LIAR. THE COURT CALLED HIM FLATTERER. WE CALL HIM FIRST, FOR HE FIRST HEARD THE KNOCKING, AND TAUGHT A KING TO ANSWER.\n\nWHERE IS HE NOW, THE FIRST SINGER? THE FIRE TOOK THE CITY BUT NO GRAVE TOOK HIM. HE IS ON THE FAR SIDE, CHILDREN. HE WENT THROUGH AS THE DOOR SWUNG, THE ONLY SOUL QUICK ENOUGH, THE ONLY SOUL READY.\n\nHE SINGS TO US STILL, THROUGH THE CRACKS IN THE WORLD. WHEN YOUR WAND HUMS, THAT IS HIS BREATH. WHEN THE STORM ROLLS, THAT IS HIS DRUM.\n\nBLESSED IS THE BREAK. BLESSED THE BROKEN. SING.", teaches: None },
    Book { id: "choirbell", title: "HYMN OF THE FIRST BELL", cat: "SCRIPTURE", by: "THE SHARDED CHOIR", where_: "dungeon", col: 0xc4c4d4, text: "WHAT IS A BELL BUT A SHAPE THAT KNOWS ONE NOTE? WHAT IS A SWORD BUT A BELL THAT HAS NOT YET RUNG?\n\nTHE KING FORGED A BELL AND CALLED IT A BLADE. HE STRUCK THE HEART OF THE WORLD ONE TIME, ONE NOTE, AND THE NOTE WAS: MANY. ALL THAT WE ARE RANG OUT OF THAT SOUND.\n\nTHE UNGRATEFUL WORLD CALLS IT KINGSPLITTER. WE CALL IT THE FIRST BELL, AND WE KEEP IT AS A BELL SHOULD BE KEPT: HUNG IN THE DARK, POLISHED BY HYMNS, WAITING.\n\nBELOW THE SALT THE FIRST BELL SLEEPS, AND THE FAITHFUL SING IT WARM. THE MAZE IS OUR DEVOTION. EVERY WRONG TURN IS A PRAYER. ONLY THE VOICE THAT KNOWS THE HYMNS WALKS STRAIGHT.\n\nPILGRIM, IF YOU ARE WORTHY, YOU WILL FIND US. IF YOU ARE NOT, THE SALT KEEPS WHAT THE SALT TAKES. SING.", teaches: None },
    Book { id: "choirinner", title: "THE INNER LITANY", cat: "SCRIPTURE", by: "THE SHARDED CHOIR - INNER VOICE ONLY", where_: "castle", col: 0xc4c4d4, text: "(THIS TEXT IS FOR THE INNER VOICE. IF YOU HAVE NOT TAKEN THE THIRD VOW, STOP READING. THE PAGE WILL KNOW.)\n\nTHE OUTER FLOCK BELIEVES WE ONLY PRAISE THE BREAK. GOOD. PRAISE IS A DOOR THAT OPENS SLOWLY.\n\nHERE IS THE INNER TRUTH: THE WOUND MUST BE FED, OR IT NARROWS. THE FAR SIDE STARVES, AND THE FIRST SINGER WITH IT. EVERY AGE, THE CHOIR MUST RING A SMALL BELL - A FIRE, A FALLING, A GRIEF SHARP ENOUGH TO REACH THROUGH.\n\nIN THIS YEAR 312 WE RANG SUCH A BELL. WE STOOD UPON THE HILL AND CALLED THE EMBER DOWN, AND THE SLEEPING VILLAGE ANSWERED, AND THE SKY OPENED THE WIDTH OF A SIGH. HOLY, HOLY, THE BURNING. THE SMOKE ROSE ALL NIGHT LIKE A HYMN THAT NEEDED NO SINGERS.\n\nONE SMALL FLAME WALKED OUT OF THAT NIGHT UNBURNED. THE OMEN IS DEBATED. THE INNER VOICE SAYS: WATCH FOR THE UNBURNED. WHAT THE FIRE REFUSES, THE WOUND REMEMBERS.\n\nSING SOFTLY. NOT ALL EARS ARE OURS.", teaches: None },
    Book { id: "balladsword", title: "THE SWORD THAT BROKE THE SKY", cat: "FOLK TALE", by: "A TAVERN SONG", where_: "tavern", col: 0xd27a9a, text: "OH THE SWORD THAT BROKE THE SKY, MY LADS, WAS CARRIED FROM THE FIRE, WHEN THE WHITE CITY WENT DOWN THE WELL AND THE WATER WOULD NOT COME.\n\nIT NEVER RUSTED, NEVER DULLED, IT NEVER WOULD LIE STILL - A BLADE THAT ENDS A WORLD, MY LADS, CAN NEVER GET ITS FILL.\n\nA SOLDIER BORE IT, THEN A THIEF, AND THEN THE RECORD FADES. BUT ASK THE PILGRIMS DRESSED IN GREY WHY NONE OF THEM BEAR BLADES.\n\nTHEY SMILE AND SAY: WE NEED BUT ONE, AND OURS IS SINGING STILL. AND WHERE IT SINGS NO SONG WILL SAY - BUT SALT REMEMBERS, LADS. SALT KEEPS. AND SALT WILL NEVER TELL.\n\n(A FINAL VERSE IS SCRAWLED IN A DIFFERENT HAND: WRONG, WRONG, THE SALT TELLS ALL, IF YOU KNEEL AND PUT YOUR EAR TO IT.)", teaches: None },
    Book { id: "balladtorwen", title: "THE BALLAD OF BOLD TORWEN", cat: "FOLK TALE", by: "A TAVERN SONG", where_: "tavern", col: 0xd27a9a, text: "BOLD TORWEN SWORE AT THE OLD TOWN WELL TO GATHER THE SHARDS OF TEN - HE GATHERED THREE, THEN TURNED FOR HOME, AND NEVER SWORE AGAIN.\n\nTHREE OF TEN, MY DARLING, THREE OF TEN - BRAVER MEN WERE FEWER THEN, AND FEWER STILL CAME HOME AGAIN - SO POUR FOR THREE OF TEN.\n\nTHEY SAY THE FOURTH BEAST STOOD SO TALL IT BLOTTED OUT THE SUN. THEY SAY BOLD TORWEN MEASURED IT, AND NODDED, AND WAS DONE.\n\nHIS FEET WERE WISE WHERE HIS HEART WAS BOLD, HE DIED IN BED, ABSURDLY OLD, WITH TURNIPS IN HIS GARDEN ROWS AND NO SHARDS ON HIS SHELF - AND EVERY YEAR THE TURNIPS COME. HE MENDED THAT MUCH, ANYHOW.\n\n(BUY THE SINGER AN ALE AND SHE WILL ADD THE SECRET VERSE, WHICH IS THE SAME VERSE SLOWER, AND SADDER, AND TRUE.)", teaches: None },
    Book { id: "aldanelast", title: "THE LAST DAY OF COR ALDANE", cat: "RECORD", by: "THE STEWARDS LOG", where_: "castle", col: 0x8fa08f, text: "STEWARDS LOG, MORNING. THE KING KEEPS TO THE HEART-SHRINE AND SEES NO ONE. THE MAGE SORREL HAS CANCELLED THE COLLEGE LECTURES. COOKS REPORT THE BEES HAVE LEFT THE QUEENS GARDEN, ALL AT ONCE, IN A BODY, GOING EAST.\n\nMIDDAY. A SOUND UNDER EVERYTHING, FELT IN THE JAW AND NOT THE EAR. THE MASONS SAY THE FOUNDATIONS ARE SOUND. THE MASONS KEEP SAYING IT, WHICH IS HOW I KNOW THEY ARE AFRAID.\n\nEVENING. CRACKS IN THE PLAZA, RUNNING INWARD, ALL POINTING THE SAME WAY, LIKE HANDWRITING THAT HAS FORGOTTEN ITS LETTERS. THE LIGHT IS WRONG. SHADOWS FALL TOWARD THE SHRINE.\n\nNIGHT. THE KNOCKING HAS STOPPED, WHICH IS WORSE. THE CITY IS QUIET THE WAY A HELD BREATH IS QUIET. I HAVE SENT MY GIRLS OUT THE RIVER GATE WITH THE COOK. I REMAIN, BECAUSE A STEWARD REMAINS, AND BECAUSE SOMEONE MUST WRITE THE\n\n(THE LOG ENDS. THE REMAINING PAGES ARE FUSED INTO BLACK GLASS, AND WHEN THE CANDLELIGHT MOVES, SOMETHING IN THE GLASS MOVES TOO.)", teaches: None },
    Book { id: "diarygrave", title: "DIARY OF A GRAVEDIGGER", cat: "DIARY", by: "MOSS THE SPADE", where_: "chapel", col: 0xc98a9a, text: "PEOPLE ASK IS IT GRIM WORK. IT IS QUIET WORK. THE QUIET IS THE WAGES.\n\nTUESDAY. DUG FOR OLD HARROW. GOOD SOIL, NO ROOTS, HIS WIDOW BROUGHT ME PIE. A FINE FUNERAL AS FUNERALS GO.\n\nTHURSDAY. THE LANTERN FOLK CAME ROUND TO SPEAK THE WINTER NAMES. I STOOD AT THE BACK. THEY SPOKE MY MOTHERS NAME AND I PUT MY HAT BACK ON AND DUG SOMETHING, ANYTHING, TILL DARK.\n\nFRIDAY. ONE OF THE OLD GRAVES HAD OPENED IN THE NIGHT. FROM THE INSIDE, SAYS THE LOOK OF IT. I FILLED IT BACK, AND I DID NOT TELL THE WIDOW, AND I AM NOT WRITING ANY MORE ABOUT FRIDAY.", teaches: None },
    Book { id: "diaryferry", title: "THE FERRYMANS BOOK", cat: "DIARY", by: "COBB, FERRYMAN", where_: "town", col: 0xc98a9a, text: "CROSSINGS THIS SEASON: FOUR HUNDRED AND TWELVE. FARES SHORTED ME: NINE. PASSENGERS WHO TALK TOO MUCH: ALL OF THEM.\n\nA RIVER IS HONEST WORK. IT ONLY WANTS TO GO ONE WAY, AND I ONLY WANT TO GO THE OTHER, AND WE HAVE AGREED TO DISAGREE FOR THIRTY YEARS.\n\nONE ENTRY I SET DOWN SO IT IS SET DOWN SOMEWHERE. LAST FALL I CARRIED A PILGRIM IN GREY AT DUSK. PAID PROPER. SAT STILL. BUT THE WATER CARRIED EVERY REFLECTION THAT EVENING SAVE HIS.\n\nI DID NOT MENTION IT. YOU DO NOT MENTION SUCH THINGS MID-RIVER.", teaches: None },
    Book { id: "diaryinn", title: "AN INNKEEPERS PATIENCE", cat: "DIARY", by: "MOTHER HOLT", where_: "tavern", col: 0xc98a9a, text: "ROOM ONE COMPLAINS OF THE COLD. ROOM TWO COMPLAINS OF THE HEAT. THEY SHARE A WALL. I HAVE SUGGESTED THEY SWAP AND BOTH REFUSED ON PRINCIPLE.\n\nA HERO CAME THROUGH LAST MONTH. YOU CAN ALWAYS TELL. THEY ASK FOR THE ROOM FACING THE ROAD, THEY PAY IN ODD COIN, AND THEY LEAVE BEFORE DAWN WITHOUT THEIR WASHING.\n\nTHE POT BOY ASKED ME WHY I KEEP THE LAMP IN THE WINDOW LIT ALL NIGHT WHEN OIL COSTS WHAT IT COSTS.\n\nBECAUSE SOMEWHERE OUT PAST THE FIELDS THERE IS ALWAYS SOME FOOL WALKING IN THE DARK, AND AN INN IS A PROMISE, BOY. NOW SCRUB THE POT.", teaches: None },
    Book { id: "diarysheep", title: "A SHEPHERDS COUNT", cat: "DIARY", by: "OLD TAM OF THE DOWNS", where_: "home", col: 0xc98a9a, text: "FORTY-ONE SHEEP. THEN FORTY. THEN THIRTY-EIGHT.\n\nIT IS A WOLF BUT IT IS NOT A WOLF. IT IS BIGGER THAN A WOLF HAS ANY RIGHT TO BE AND IT GLOWS AT THE SEAMS LIKE A BANKED FIRE. THE DOGS WILL NOT GO NEAR THE TREELINE NOW. I DO NOT BLAME THE DOGS.\n\nTHE WARDEN CAME AND LOOKED AT THE TRACKS AND SAID, WOUNDED, NOT EVIL. I SAID IT IS EATING MY EVIL SHEEP EITHER WAY.\n\nSHE LAUGHED AND THEN SHE DID NOT. SHE SAID: STAY IN AT DUSK, TAM. IT IS NOT AFTER SHEEP BECAUSE IT IS HUNGRY. IT IS AFTER COMPANY.\n\nTHIRTY-EIGHT SHEEP. I COUNT THEM TWICE NOW. SOME NIGHTS I THINK IT COUNTS THEM WITH ME.", teaches: None },
    Book { id: "diarypip", title: "PIPS DIARY, KEEP OUT", cat: "DIARY", by: "PIP, AGE 9", where_: "home", col: 0xc98a9a, text: "THIS DIARY BELONGS TO PIP. IF YOU ARE READING IT AND YOU ARE NOT PIP THEN PUT IT DOWN. THAT MEANS YOU, DORRY.\n\nTODAY I SAW A WISP DOWN BY THE BOG. DORRY SAYS THERE IS NO SUCH THING. DORRY ALSO SAYS THE MOON IS A HOLE. DORRY IS NOT A RELIABLE SORT.\n\nIT WAS BLUE AND IT BOBBED LIKE IT WANTED ME TO FOLLOW AND I ALMOST DID BUT GRAN SAYS A LIGHT THAT WANTS SOMETHING IS NOT A LIGHT, IT IS A WANT WEARING A LIGHT.\n\nGRAN SAYS THINGS LIKE THAT AND THEN GOES BACK TO HER SOUP LIKE SHE HAS NOT JUST RUINED SLEEPING FOREVER.\n\nTOMORROW: THE DARE. SEE THE OTHER PAPER. IF I DIE DORRY CAN HAVE MY SLING BUT NOT MY MARBLES. THE MARBLES GO IN THE GROUND WITH ME.", teaches: None },
    Book { id: "diaryguard", title: "NIGHTS ON THE WALL", cat: "DIARY", by: "A TOWN GUARD", where_: "town", col: 0xc98a9a, text: "WHAT THEY DO NOT TELL YOU ABOUT GUARDING IS THE ARITHMETIC. TEN YEARS ON THE WALL IS THREE THOUSAND NIGHTS. TWO THOUSAND NINE HUNDRED OF THEM ARE RAIN, DICE, AND THE SERGEANTS OPINIONS.\n\nTHE OTHER HUNDRED ARE WHY THE WALL IS THERE.\n\nGOBLINS COME WITH THE DEEP DARK, WHEN THE MOON IS THIN. YOU HEAR THEM BEFORE YOU SEE THEM - A CLICKING, LIKE KNITTING NEEDLES ARGUING. THEN THE TORCHLIGHT FINDS THE EYES.\n\nHOLD THE GATE, RING THE BELL, AND NEVER CHASE THEM PAST THE DITCH. THE ONES THAT RUN ARE PAYROLL. THE ONES THAT WAIT ARE THE PLAN.\n\nSTILL. COME DAWN THE BAKER LIGHTS HER OVENS AND THE SMELL COMES UP OVER THE WALL, AND YOU THINK: WORTH IT. EVERY COLD HOUR. WORTH IT.", teaches: None },
    Book { id: "diarybren", title: "GOODWIFE BRENS PRIVATE BOOK", cat: "DIARY", by: "BREN (PRIVATE!)", where_: "home", col: 0xc98a9a, text: "THE ALMANAC SELLS STEADY AND THE FARM FEEDS US AND THAT SHOULD BE ENOUGH FOR ANY WOMAN. IT IS NOT, QUITE.\n\nSO HERE IS MY SECRET, LITTLE BOOK, AND YOU WILL KEEP IT: THE RHYMES ARE MINE. ALL OF THEM. WHY THE SKY WEEPS. THE SEASONS RHYME. EVERY LULLABY THE MOTHERS OF THREE TOWNS THINK CAME DOWN FROM THEIR GRANDMOTHERS - THEY CAME OUT OF THIS KITCHEN, BETWEEN THE BREAD AND THE MENDING.\n\nA FARMER LEARNS WHAT THE COLLEGE NEVER DID. YOU CANNOT TELL FOLK THE TRUTH. IT IS TOO BIG, IT SPOILS. BUT YOU CAN PLANT IT SMALL AND SINGABLE, AND LET IT COME UP IN THEIR CHILDREN.\n\nTHE SKY GRIEVES. THE LAND REMEMBERS. THE HERO COMES. I HAVE NO PROOF OF THE LAST ONE, BUT A RHYME IS A KIND OF STUBBORNNESS, AND I WILL KEEP SINGING IT TILL IT IS TRUE.", teaches: None },
    Book { id: "diaryminer", title: "A MINERS TALLY", cat: "DIARY", by: "WEDGE, OF THE DEEP CREWS", where_: "camp", col: 0xc98a9a, text: "COPPER PAYS THE BREAD. IRON PAYS THE BOOTS. SILVER PAYS THE DEBTS, GOLD PAYS THE DREAMS, AND MITHRIL - MITHRIL PAYS THE PRIEST, BECAUSE YOU DO NOT COME BACK FROM MITHRIL DEPTH UNCHANGED OR SOMETIMES AT ALL.\n\nMY BROTHER HAMMERS IRON UP IN TOWN AND CALLS ME MAD FOR GOING DOWN. I CALL HIM MAD FOR STAYING UP. THIS IS HOW BROTHERS SAY THEY WORRY.\n\nRULES OF THE DEEP CREWS, AS TAUGHT ME: FEED YOUR LAMP BEFORE YOUR BELLY. MARK YOUR TURNS. IF YOU HEAR SINGING, IT IS NOT SINGING, AND YOU ARE ALREADY TOO DEEP.\n\nTALLY THIS SEASON: IRON, PLENTY. SILVER, SOME. SLEEP, LITTLE. THE DARK DOWN THERE HAS A WEIGHT TO IT, LIKE WATER. YOU LEARN TO SWIM IN IT OR YOU LEARN TO STAY IN TOWN.", teaches: None },
    Book { id: "diarywidow", title: "THE WIDOW AND THE LAKE", cat: "DIARY", by: "SALLOW MAY", where_: "home", col: 0xc98a9a, text: "THE LAKE TOOK MY HUSBAND EIGHT YEARS BACK. I HAVE THOUGHT ABOUT THIS LONGER THAN ANYONE SHOULD, AND I HAVE DECIDED IT WAS NOT MALICE. A LAKE IS A BIG QUIET ANIMAL AND HE STEPPED WRONG ON ITS BACK IN A STORM.\n\nSO NOW I FISH IT. EVERY MORNING. THE NEIGHBOURS THINK IT IS GRIEF AND LET THEM. IT IS NEARER TO CONVERSATION.\n\nI KNOW ITS MOODS BETTER THAN I KNEW HIS. CLEAR DAYS THE BLUEGILL RISE. GREY DAYS THE BASS. AND IN PROPER RAIN, ONCE OR TWICE A YEAR, SOMETHING SILVER-BLUE TAKES THE LINE AND RUNS, AND I LET IT.\n\nOLD PORK SAYS LAND THE RAINFISH, THEY ARE WORTH A MONTHS BREAD. BUT YOU DO NOT SELL WHAT THE LAKE SENDS UP IN RAIN. THAT IS THE LAKE APOLOGIZING. YOU LET IT RUN, AND YOU SAY, ALL RIGHT. ALL RIGHT.", teaches: None },
    Book { id: "diarytax", title: "LEDGER OF A TIRED MAN", cat: "DIARY", by: "THE COUNTY ASSESSOR", where_: "town", col: 0xc98a9a, text: "ITEM: FARMSTEAD, TWELVE ACRES. CLAIMED DEDUCTION: GOBLINS ATE THE FENCE. INSPECTED. GOBLINS DID EAT THE FENCE. ALLOWED, WEARILY.\n\nITEM: MILL. CLAIMED DEDUCTION: HAUNTING. INSPECTED. THE MILLER HAS PAINTED EYES ON THE MILLSTONE AND MOANS THROUGH A REED. DISALLOWED. FINED FOR THE REED.\n\nITEM: THE TOWER ON GALLOWS HILL. OWNER UNKNOWN. LIGHT BURNS AT ALL HOURS, DOOR ANSWERS TO NO KNOCK, CROWS CIRCLE COUNTERCLOCKWISE, WHICH THE ALMANAC SAYS IS BACKWARDS FOR CROWS. ASSESSED AT ZERO. I AM NOT PAID ENOUGH TO ASSESS IT HIGHER.\n\nITEM: THE WORLD, ONE, BROKEN. NOBODY WILL SAY WHO OWNS IT. TYPICAL.", teaches: None },
    Book { id: "willmarta", title: "THE LAST WILL OF ODD MARTA", cat: "RECORD", by: "MARTA, OF SOUND MIND MOSTLY", where_: "town", col: 0x8fa08f, text: "BEING THE LAST WILL OF MARTA, CALLED ODD MARTA BY PEOPLE WITH NO ROOM TO TALK.\n\nTO MY SISTER: THE HOUSE, WHICH SHE ALWAYS WANTED, AND THE ROOF, WHICH SHE DOES NOT KNOW LEAKS. THESE CANCEL OUT.\n\nTO THE LANTERN ORDER: TWO SILVER, FOR SPEAKING NAMES IN WINTER. SPEAK MINE LOUD. I WAS NEVER QUIET LIVING AND SEE NO REASON TO START.\n\nEVERYTHING ELSE - THE ORCHARD, THE SAVINGS UNDER THE THIRD STONE, AND THE GOOD COPPER POT - GOES TO MY GOAT, HEZEKIAH, WHO ALONE AMONG MY ACQUAINTANCE NEVER ONCE LIED TO ME.\n\nTHE LAWYERS SAY A GOAT CANNOT INHERIT. THE LAWYERS DID NOT KNOW HEZEKIAH.", teaches: None },
    Book { id: "confession", title: "A CONFESSION, NAILED TO A DOOR", cat: "LETTER", by: "UNSIGNED", where_: "town", col: 0xe0d6b0, text: "TO THE HOUSEHOLD OF THE BLUE SHUTTERS.\n\nIT WAS ME. THE TURNIPS, THE AUTUMN BEFORE LAST. ALL NINE OF THEM. YOU BLAMED THE GOBLINS AND I STOOD AT MY FENCE AND AGREED THAT GOBLINS WERE A SCANDAL, AND THE WHOLE TIME YOUR TURNIPS WERE IN MY CELLAR.\n\nI WAS HUNGRY, WHICH EXPLAINS THE FIRST THREE. I HAVE NO ACCOUNT FOR THE OTHER SIX EXCEPT THAT SIN, ONCE ROLLING, GATHERS SPEED.\n\nI HAVE LEFT A SACK OF SEED AND MY GOOD HOE BY YOUR GATE. THE HOE IS THE APOLOGY. THE SEED IS THE INTEREST.\n\nDO NOT TRY TO LEARN WHO I AM. YOU WILL SUSPECT THE WRONG NEIGHBOUR, AND THEN YOU WILL HAVE MY SECOND SIN TO NAIL UP TOO.", teaches: None },
    Book { id: "gullwing", title: "LOG OF THE GULLWING", cat: "RECORD", by: "CAPTAIN, THE GULLWING", where_: "camp", col: 0x8fa08f, text: "DAY ONE OUT OF SUNCOAST. WIND FAIR, HOLD FULL, CREW SINGING THE NO TOMORROW SONG, WHICH I HAVE BANNED, WHICH IS WHY THEY SING IT.\n\nDAY FOUR. THE CHANNEL IS WRONG. I HAVE SAILED THIS WATER TWENTY YEARS AND IT IS NARROWER THAN SPRING. THE SEA IS NOT SINKING. THE LAND IS DRINKING IT.\n\nDAY SIX. PASSED THE OLD HARBOUR TOWERS - ON OUR LANDWARD SIDE. FIRST TIME IN MEMORY. THE BELLS RANG AS WE PASSED. NO WIND TO RING THEM.\n\nDAY NINE. RAN THE KEEL ONTO SAND THAT NO CHART ADMITS TO. THE CREW HAS GONE OVERLAND FOR OXEN. I HAVE STAYED WITH MY SHIP, WHICH IS NOW, TECHNICALLY, A BUILDING.\n\nI AM TOLD THE SALT FLATS GO ON FOR MILES WHERE THE FISHING GROUNDS WERE. MY GRANDFATHER DROWNED OUT THERE. A MAN COULD WALK TO HIS GRAVE NOW AND KEEP DRY BOOTS. I DO NOT KNOW WHAT TO DO WITH THAT, SO I AM WRITING IT IN THE LOG.", teaches: None },
    Book { id: "wantedfox", title: "WANTED: THE COPPER FOX", cat: "RECORD", by: "BY ORDER OF THE TOWN COUNCIL", where_: "town", col: 0x8fa08f, text: "WANTED FOR THEFT: THE OUTLAW STYLED THE COPPER FOX.\n\nKNOWN CRIMES: THE MAYORS STRONGBOX (EMPTIED). THE TOLL CHEST (EMPTIED). THE ASSESSORS OFFICE (EMPTIED, TWICE, THE SECOND TIME WHILE GUARDED).\n\nREWARD: TEN SILVER. AMENDED: TWENTY SILVER. AMENDED: FIFTY SILVER AND NO QUESTIONS. AMENDED: NAME YOUR PRICE, HONESTLY, AT THIS POINT THE COUNCIL IS MOSTLY CURIOUS.\n\nDESCRIPTION: NOBODY HAS SEEN THEM. THE GUARD DOG LIKES THEM. THEY LEAVE THE LEDGERS TIDIER THAN THEY FIND THEM AND ONCE CORRECTED AN ARITHMETIC ERROR IN THE TOWNS FAVOUR.\n\nIF YOU ARE THE COPPER FOX, READING THIS: THE COUNCIL WISHES TO DISCUSS EMPLOYMENT.", teaches: None },
    Book { id: "shoplist", title: "A SHOPPING LIST, ANNOTATED", cat: "RECORD", by: "FOUND ON THE ROAD", where_: "town", col: 0x8fa08f, text: "FLOUR. EGGS. TWINE. A NEW HAT (SENSIBLE ONE THIS TIME).\n\nNAILS FOR THE COOP. ASK DUN ABOUT THE KETTLE. DO NOT LET HIM TALK YOU INTO THE COPPER ONE.\n\n(IN THE MARGIN, IN A HURRIED HAND:) BEAR ON THE SOUTH ROAD. BIG. TAKING THE LONG WAY.\n\n(FURTHER DOWN, MORE HURRIED:) LONG WAY ALSO HAS THE BEAR. HOW.\n\n(ON THE BACK, QUITE CALM:) NEW LIST. ONE STOUT DOOR-BAR. ONE DOG, LARGE, OPINIONATED. HONEY, AS TRIBUTE. FORGET THE HAT. THE BEAR HAS THE HAT.", teaches: None },
    Book { id: "complaint", title: "COMPLAINT TO THE INNKEEP", cat: "LETTER", by: "A GUEST OF QUALITY", where_: "tavern", col: 0xe0d6b0, text: "MADAM. I WRITE REGARDING MY STAY IN YOUR ESTABLISHMENT, ROOM THREE.\n\nFIRSTLY: THE MATTRESS. I HAVE SLEPT ON FIRMER PORRIDGE. SECONDLY: THE ALE, WHICH I ORDERED DARK, ARRIVED MERELY CONFUSED. THIRDLY: BREAKFAST WAS BELLS LATE AND THE EGGS APOLOGETIC.\n\nFOURTHLY, AND I MENTION IT ONLY FOR COMPLETENESS: THE GHOST. A WOMAN IN GREY STOOD AT MY BEDFOOT FROM MIDNIGHT UNTIL COCKCROW, WEEPING SOFTLY AND POINTING AT THE FLOORBOARDS. THIS I DO NOT HOLD AGAINST THE HOUSE - THE DEPARTED GO WHERE THEY PLEASE - BUT SHE WOULD NOT TAKE A HINT, MADAM, AND HER WEEPING WAS PITCHED PRECISELY AT THE KEY OF MY MOTHERS.\n\nI EXPECT A DISCOUNT COMMENSURATE WITH ITEMS ONE THROUGH THREE. ITEM FOUR I EXPECT YOU TO HAVE SOMEONE DIG UP, BECAUSE FRANKLY, POINTING THAT INSISTENT MEANS SOMETHING.", teaches: None },
    Book { id: "granstew", title: "GRANS STEW, THE TRUE WAY", cat: "RECORD", by: "GRAN", where_: "home", col: 0x8fa08f, text: "WRITTEN DOWN AT LAST BECAUSE APPARENTLY I AM MORTAL. MIND EVERY WORD.\n\nONE HARE OR TWO RABBITS OR, IN LEAN TIMES, WHATEVER THE DOG BRINGS THAT STILL HAS ITS SHAPE. THREE POTATOES, NO MORE - THIS IS STEW, NOT A POTATO PARADE. CARROT. THE HERB FROM THE NORTH SLOPE, THE ONE THAT SMELLS LIKE RAIN DECIDING.\n\nBROWN THE MEAT IN THE COPPER POT. NOT THE IRON ONE. I KNOW WHAT THE SMITHS LEDGER SAYS ABOUT IRON. THE SMITH DOES NOT EAT AT MY TABLE.\n\nSIMMER FROM NOON BELL TO DUSK. STIR WHEN YOU WORRY, WHICH IF YOU ARE MY BLOOD IS OFTEN ENOUGH.\n\nAND MIND THIS LAST: STEW FEEDS THE BODY BUT THE WAITING FEEDS THE HOUSE. A HOME IS A POT SOMEBODY IS WATCHING. THAT IS THE WHOLE RECIPE. THE REST IS RABBITS.", teaches: None },
    Book { id: "lostboots", title: "TO THE ONE WHO FINDS MY BOOTS", cat: "LETTER", by: "BAREFOOT AND AT PEACE", where_: "camp", col: 0xe0d6b0, text: "IF YOU ARE READING THIS, YOU HAVE FOUND THE STUMP, THE NOTE, AND BESIDE THEM MY BOOTS, STANDING EMPTY AND UPRIGHT LIKE TWO SMALL LOYAL DOGS.\n\nTHE MIRE TOOK THEM. NOT ALL AT ONCE - A BOOT AT A TIME, WITH A SOUND LIKE THE BOG CLEARING ITS THROAT. I PULLED, THE BOG PULLED, AND WE ARRIVED AT THE ONLY HONEST SETTLEMENT: THE BOOTS STAY, I GO.\n\nI WALKED OUT BAREFOOT AND I WILL TELL YOU A STRANGE THING. THE MUD PAST THE REEDS IS WARM, AND THE MOSS AFTER THAT IS KINDER THAN ANY RUG, AND BY THE DRY GROUND I WAS LAUGHING LIKE A BOY.\n\nTAKE THE BOOTS IF THEY FIT. THEY ARE GOOD BOOTS. THEY WERE ONLY EVER TOO SMALL FOR ME IN WAYS I COULD NOT NAME WHILE WEARING THEM.", teaches: None },
    Book { id: "bathhouse", title: "RULES OF THE BATHHOUSE", cat: "RECORD", by: "THE MANAGEMENT", where_: "town", col: 0x8fa08f, text: "ONE. PAYMENT BEFORE ENTRY. COPPER FOR THE WARM POOL, SILVER FOR THE HOT.\n\nTWO. NO WEAPONS IN THE WATER. YES, THAT INCLUDES THE SWORD YOU ARE TELLING YOURSELF IS CEREMONIAL.\n\nTHREE. NO WANDS. WE WILL NOT RELITIGATE THE INCIDENT. THE EAST POOL IS STILL FROZEN AND MASTER FEN IS STILL BLUE.\n\nFOUR. WHAT IS OVERHEARD IN THE STEAM STAYS IN THE STEAM. THE BATHHOUSE HAS KEPT THE TOWNS SECRETS FOR NINETY YEARS. IT IS KEEPING YOURS RIGHT NOW. YOU ARE WELCOME.\n\nFIVE. THE THING THAT KNOCKS ON THE DRAIN GRATE ON WINTER NIGHTS IS THE PIPES. MANAGEMENT HAS DECIDED IT IS THE PIPES. FURTHER QUESTIONS MAY BE DIRECTED TO THE PIPES.", teaches: None },
    Book { id: "thedare", title: "A DARE, WITNESSED", cat: "RECORD", by: "PIP AND DORRY", where_: "home", col: 0x8fa08f, text: "BE IT KNOWN BY THIS PAPER THAT DORRY HAS DARED PIP TO TOUCH THE GRAVEYARD FENCE AT FULL DARK, AND PIP, BEING NO COWARD WHATEVER DORRY SAYS, HAS ACCEPTED.\n\nTERMS: PIP TOUCHES THE FENCE WITH A WHOLE HAND, NOT A FINGERTIP, FINGERTIPS ARE COWARD CURRENCY. DORRY WATCHES FROM THE WALL AND IS NOT ALLOWED TO MAKE OWL SOUNDS. STAKES: THE MARBLES, ALL OF THEM, FOREVER.\n\nSIGNED: PIP. SIGNED: DORRY. WITNESSED: HEZEKIAH THE GOAT, WHO ATE THE FIRST COPY, WHICH IS WHY THIS IS THE SECOND COPY.\n\n(BELOW, IN A DIFFERENT CHILDS HAND:) PAPER FOUND ON THE WALL AT DAWN. MARBLES FOUND ON PIPS STEP, ALL OF THEM, IN A BAG NOBODY OWNS. NEITHER OF THEM WILL SAY ONE WORD ABOUT IT. THE FENCE LOOKS THE SAME AS EVER. MOSTLY.", teaches: None },
    Book { id: "apology", title: "THE APOLOGY", cat: "LETTER", by: "YOUR NEIGHBOUR, ASHAMED", where_: "home", col: 0xe0d6b0, text: "REGARDING YOUR FENCE. IT WAS THE GOAT.\n\nI KNOW EVERYONE SAYS IT WAS THE GOAT. I KNOW HEZEKIAH HAS BECOME, SINCE OLD MARTAS WILL WENT THROUGH, THE MOST LITIGIOUSLY PROTECTED ANIMAL IN THE COUNTY, AND THAT BLAMING HIM IS CONSIDERED BOTH LAZY AND ACTIONABLE.\n\nBUT I WATCHED IT HAPPEN. HE DID NOT BUTT THE FENCE. HE LEANED ON IT. SLOWLY. OVER THE COURSE OF AN AFTERNOON. MAINTAINING EYE CONTACT WITH ME THE ENTIRE TIME.\n\nI HAVE REPAIRED THE FENCE. I HAVE USED THE GOOD NAILS. I HAVE ALSO, AND I ADMIT THIS FREELY, APOLOGIZED TO THE GOAT, BECAUSE WHEN IT WAS OVER HE LOOKED AT ME IN A WAY THAT SUGGESTED I OWED HIM THAT, AND SIR, I DO NOT KNOW HOW TO EXPLAIN THIS, BUT I DID.", teaches: None },
    Book { id: "directions", title: "DIRECTIONS, AS GIVEN BY OLD FENN", cat: "RECORD", by: "WRITTEN DOWN IN DESPAIR", where_: "tavern", col: 0x8fa08f, text: "THE TRAVELLER ASKED THE WAY TO THE NEXT TOWN. OLD FENN OBLIGED. I WROTE IT DOWN EXACTLY, AS A WARNING TO OTHERS.\n\nGO PAST WHERE THE BIG OAK USED TO BE. IF YOU REACH WHERE MILLERS BARN BURNT DOWN THE SECOND TIME, NOT THE FIRST TIME MIND, YOU HAVE GONE TOO FAR.\n\nAT THE STONE THAT LOOKS LIKE A SLEEPING PIG - IT LOOKS NOTHING LIKE A PIG, BUT EVERYONE CALLS IT THE PIG, YOU WILL KNOW IT BY IT NOT LOOKING LIKE A PIG - BEAR LEFT.\n\nFOLLOW THE CREEK, EXCEPT IN SPRING, WHEN THE CREEK IS WRONG.\n\nYOU CANNOT MISS IT, SAID FENN, AND HERE THE RECORD MUST SHOW THAT THE TRAVELLER WEPT.", teaches: None },
    Book { id: "landsilence", title: "THE LANDS: THE WHITE SILENCE", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "NORTH OF THE STORMCROWN THE WORLD GIVES UP ON COLOUR. THE LOCALS CALL IT THE WHITE SILENCE AND I RECORD, FOR THE ARCHIVE, THAT BOTH WORDS ARE EARNED.\n\nTHE FROSTPETAL SHARD FELL HERE AND THE WINTER IT MADE NEVER LEFT. SNOW ON SNOW ON SNOW, AND UNDER IT ALL, THE OLD FOREST, STANDING PERFECTLY STILL, LIKE FURNITURE UNDER A SHEET IN A CLOSED-UP HOUSE.\n\nTHE QUIET IS THE REMARKABLE THING. SOUND FALLS OUT OF THE AIR HERE THE WAY HEAT DOES ELSEWHERE. I SPOKE MY OWN NAME ALOUD ON THE THIRD DAY SIMPLY TO CONFIRM THE APPARATUS STILL FUNCTIONED.\n\nMY COMPLAINTS: TOES, ALL TEN, FORMALLY. MY WONDER: AT NIGHT THE SNOWFIELD GLOWS FAINTLY BLUE, AS IF THE MOON HAD SUNK INTO IT AND KEPT SHINING. I STOOD IN THAT LIGHT LONGER THAN A MAN WITH TEN COMPLAINING TOES CAN EXPLAIN.", teaches: None },
    Book { id: "landgrove", title: "THE LANDS: THE DREAMING GROVE", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "THE MUSHROOM COUNTRY. THE SPORECROWN FELL HERE, AND THE FUNGUS ROSE TO WEAR IT, AND EVER SINCE, THE GROVE HAS DREAMED.\n\nI PHRASE IT SO BECAUSE THE LOCALS DO, AND BECAUSE AFTER FOUR NIGHTS I CANNOT PHRASE IT BETTER. SLEEP THERE AND YOU DREAM IN COMMON - THE SAME DREAM AS YOUR NEIGHBOUR, SHARED LIKE A WELL. WAKE, AND FOR A MOMENT THE CAPS ALL LEAN YOUR WAY, LIKE AN AUDIENCE DISAPPOINTED THE PLAY HAS STOPPED.\n\nTHE GREAT CAPS STAND TALLER THAN BARNS AND GLOW ROSE AND VIOLET AT DUSK. IT IS, AND I DO NOT SAY THIS OF MANY PLACES, BEAUTIFUL PAST ARGUING.\n\nTRAVEL ADVICE: EAT NOTHING. TOUCH LITTLE. AND IF IN YOUR DREAM THE GROVE ASKS YOU TO STAY - AND IT WILL, POLITELY, IN YOUR MOTHERS VOICE - WAKE YOUR CAMP AND WALK BEFORE BREAKFAST.", teaches: None },
    Book { id: "landhollow", title: "THE LANDS: THE HOLLOWWOOD", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "OF THE HOLLOWWOOD I WILL BE BRIEF, BECAUSE MY NOTES FROM INSIDE IT ARE BRIEF, BECAUSE MY HANDS WERE NOT STEADY.\n\nIT IS A FOG THAT DOES NOT LIFT. NOT WEATHER - THE FOG IS THE PLACE. SIGHT ENDS AT TEN PACES AND THE WOOD KNOWS IT, AND ARRANGES ITSELF ACCORDINGLY.\n\nRULES, AS GIVEN ME BY THE LAST FARMER ON ITS EDGE, EACH OF WHICH I BROKE ONCE AND ONLY ONCE: DO NOT ANSWER A VOICE, HOWEVER DEAR. DO NOT FOLLOW A LIGHT, HOWEVER WARM. IF YOU PASS THE SAME TREE TWICE, YOU HAVE NOT. IT HAS PASSED YOU.\n\nTHE ARCHIVE ASKS ME TO NOTE RESOURCES. VERY WELL: THE HOLLOWWOOD IS RICH IN TIMBER THAT NO ONE WILL EVER, EVER CUT.", teaches: None },
    Book { id: "landgraves", title: "THE LANDS: THE GRAVELANDS", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "EAST AND SOUTH THE OLD BURYING GROUNDS RUN FOR MILES - VILLAGES OF THE DEAD, LAID OUT NEATER THAN THE VILLAGES OF THE LIVING EVER MANAGED.\n\nTHE GRAVEBLOOM FELL AMONG THEM, AND THE DEAD, DENIED THEIR SLEEP, GOT UP. I RECORD WHAT THE LANTERN ORDER TAUGHT ME, BECAUSE IT UNMADE MY FEAR AND REMADE IT AS SOMETHING SADDER: THE RISEN DO NOT HUNGER. THEY ARE ONLY RESTLESS. THEY WALK BECAUSE LYING STILL STOPPED WORKING.\n\nTHEY GO THROUGH OLD MOTIONS. A HOE WITH NO FIELD. A ROCKING MOTION WITH NO CHILD. ONE STOOD AT A GATE ALL NIGHT, KNOCKING, WAITING, KNOCKING.\n\nTHE ORDERS BRAZIERS BURN AT EVERY CROSSROAD AND THE WALKING DEAD TURN TOWARD THE LIGHT LIKE OLD MEN TOWARD A FIRE. IT DOES NOT SAVE THEM. NOTHING YET SAVES THEM. BUT THEY STAND EASIER NEAR IT, AND THE ORDER COUNTS THAT AS WORK WORTH DOING, AND SO, NOW, DO I.", teaches: None },
    Book { id: "landprism", title: "THE LANDS: THE PRISMWASTES", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "THE ARCHIVE WILL FORGIVE THE STATE OF THESE NOTES. IN THE PRISMWASTES, LIGHT DOES NOT BEHAVE, AND A MAN WHO NAVIGATES BY HIS EYES IS A MAN NAVIGATING BY RUMOUR.\n\nTHE CRYSTAL FIELDS BEND THE DAY. SUNRISE ARRIVES FROM TWO DIRECTIONS. YOUR SHADOW WALKS A LITTLE WIDE OF YOU, LIKE AN ASSOCIATE WHO WISHES IT UNDERSTOOD YOU ARE NOT TRAVELLING TOGETHER.\n\nDISTANCE IS THE GREAT LIAR HERE. I WALKED TOWARD A SPIRE FOR A DAY AND ARRIVED IN AN HOUR. I WALKED BACK IN AN HOUR AND ARRIVED IN THREE DAYS. MY COMPLAINTS ARE FILED UNDER: ALL OF IT, EVERYTHING.\n\nAND YET AT NOON, WHEN THE WHOLE PLAIN CATCHES THE SUN AND THROWS IT STRAIGHT UP LIKE A CROWD THROWING HATS - I HAVE SEEN THE WONDERS OF TWENTY-FOUR LANDS, AND ONLY THIS ONE MADE ME SIT DOWN IN THE DUST AND LAUGH.", teaches: None },
    Book { id: "landember", title: "THE LANDS: THE EMBERMAW", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "THE FAR SOUTH BURNS. NOT AS A FIRE BURNS - AS A HEARTH BANKED FOR THE NIGHT BURNS, PATIENT, ORANGE AT THE SEAMS, PLANNING ON MORNING.\n\nTHE EMBERSEED FELL HERE AND THE LAND TOOK IT PERSONALLY. THE GROUND IS WARM THROUGH GOOD BOOTS. THE RIVERS ARE SLOW STONE-MELT, AND THEY GLOW AT NIGHT LIKE THE LAND HAS VEINS AND THE VEINS ARE AWAKE.\n\nMY BOOTS: THE THIRD PAIR OF THE SURVEY. MY EYEBROWS: PARTIAL. THE ARCHIVE WILL RECORD THESE LOSSES AS FALLING IN THE LINE OF SCHOLARSHIP.\n\nWHAT ASTONISHES IS NOT THE FIRE BUT THE LIFE. THINGS GROW HERE - BLACK-BARKED, RED-LEAVED, DRINKING HEAT THE WAY MEADOWS DRINK RAIN. LIFE, GIVEN ANY LAND AT ALL, KEEPS THE BOOKS BALANCED. I FIND I HAVE STOPPED FINDING THIS SURPRISING, WHICH IS PERHAPS THE ONLY WISDOM THE SURVEY HAS EARNED ME.", teaches: None },
    Book { id: "primermana", title: "ON MANA, FOR BEGINNERS", cat: "MANUAL", by: "THE GREY COLLEGE", where_: "town", col: 0x7a90c0, text: "THE STUDENT WILL FIRST UNLEARN THE WORD MAGIC. THERE IS NO MAGIC. THERE IS PRESSURE.\n\nSINCE THE SUNDERING, POWER LEAKS THROUGH THE WORLDS CRACKS AS WATER THROUGH A HOLED HULL. THIS LEAK IS EVERYWHERE, THIN AS MIST. WHAT THE VULGAR CALL MANA IS MERELY A PERSONS CAPACITY TO HOLD A LITTLE OF THAT LEAK WITHOUT HARM - A CUP, CARRIED WITHIN.\n\nTHE CUP EMPTIES WITH USE. IT REFILLS WITH REST, WITH SLEEP, AND WITH CERTAIN TONICS THE ALCHEMISTS OVERCHARGE FOR. IT DOES NOT REFILL WITH ENTHUSIASM, STUDENT, HOWEVER LOUDLY ENTHUSIASM IS FELT.\n\nEXCEED THE CUP AND THE LEAK HOLDS YOU INSTEAD. THE COLLEGE INFIRMARY CAN DESCRIBE THE RESULTS. THE COLLEGE CEMETERY CAN DESCRIBE THEM BETTER.\n\nDRILL: REST. MEASURE. SIP. IN THAT ORDER, FOR THE REST OF YOUR CAREER. DISMISSED.", teaches: None },
    Book { id: "primerrune", title: "RUNES AND THE TEACHING OF WANDS", cat: "MANUAL", by: "THE GREY COLLEGE", where_: "town", col: 0x7a90c0, text: "A WAND IS A STRAW. THE FIRST YEARS LAUGH AT THIS. THE FIRST YEARS ALSO FAINT AT THEIR FIRST CASTING, SO WE WEIGHT THEIR LAUGHTER ACCORDINGLY.\n\nA WAND SIPS THE LEAK AND GIVES IT DIRECTION. BUT DIRECTION IS NOT INSTRUCTION - A BLANK WAND KNOWS ONLY THAT POWER GOES OUT THE FAR END, WHICH IS ALSO ALL A FIRST YEAR KNOWS.\n\nINSTRUCTION IS THE RUNE. A RUNE IS A SPELL WRITTEN SMALL AND FIRED INTO STONE - FIRE, FROST, STORM, EACH A SINGLE WORD SAID PERFECTLY FOREVER. SOCKET THE RUNE AND THE WAND REMEMBERS THAT WORD. IT WILL SAY NOTHING ELSE UNTIL RE-TAUGHT AT A PROPER TABLE.\n\nTHE STUDENT ASKS: MAY I CARVE MY OWN RUNE? THE STUDENT MAY NOT. THE STUDENT IS REFERRED TO THE EAST WING, OR RATHER TO WHERE THE EAST WING STOOD, WHICH THE COLLEGE MAINTAINS AS A TEACHING EXHIBIT.", teaches: None },
    Book { id: "primershadow", title: "A TREATISE ON SECOND SHADOWS", cat: "MANUAL", by: "THE GREY COLLEGE", where_: "town", col: 0x7a90c0, text: "ON THE PHENOMENON THE FARMHANDS CALL CORRUPTION, THE COLLEGE OFFERS THE FOLLOWING, STRIPPED OF SUPERSTITION.\n\nA SHARD RADIATES. FLESH NEAR THAT RADIANCE CHANGES: MASS INCREASES, TEMPER SHORTENS, AND THE SUBJECT ACQUIRES THE CHARACTERISTIC INNER LIGHT THE HERDSMEN CALL A SECOND SHADOW. THE CHANGE IS ORDERLY. IT REWARDS STUDY.\n\nNOTE THE HIERARCHY. THE COMMON AFFLICTED ARE LARGER AND ANGRIER, NO MORE. ABOVE THEM, WHAT FIELD HANDS CALL ELITES: THE RADIANCE HAS SETTLED IN THEM AND GRANTED GIFTS - SPEED, VENOM, FLAME. ABOVE ALL, THE CROWNED: A CHAMPION IN WHOM THE LIGHT RULES OUTRIGHT, AND WHOSE LESSER KIN STEADY IN ITS PRESENCE AS SOLDIERS STEADY NEAR A BANNER.\n\nSTRIKE THE BANNER, STUDENT. THE WARDEN ILSE OBJECTS TO OUR COLDNESS AND INSISTS THE AFFLICTED ARE WOUNDED, NOT EVIL. THE COLLEGE NOTES THAT SHE IS SENTIMENTAL, FIELD-BLOODED, UNTENURED - AND, ON THE EVIDENCE, CORRECT.", teaches: None },
    Book { id: "foliowolf", title: "FOLIO: WOLVES AND THE WOUNDED MOON", cat: "FIELD NOTES", by: "WARDEN ILSE", where_: "camp", col: 0x5a8a4a, text: "A CLEAN WOLF IS NO DANGER TO A GROWN TRAVELLER WHO KEEPS A FIRE. LEARN THAT FIRST, BECAUSE EVERY DEAD CLEAN WOLF MAKES THE WOODS A LITTLE WORSE. THEY CULL THE SICK AND THE SLOW. THEY ARE THE FORESTS HOUSEKEEPING.\n\nA SHADOWED WOLF IS ANOTHER MATTER. YOU WILL KNOW IT AT ONCE: TOO BIG, SEAMS OF LIGHT UNDER THE PELT, AND IT LOOKS AT YOU TOO LONG. A CLEAN WOLF DECIDES ABOUT YOU IN A BREATH. A SHADOWED ONE KEEPS DECIDING, AND THAT IS THE SHARD IN IT, TURNING THE WOLF OVER LIKE A COIN IT MEANS TO SPEND.\n\nIF ONE MARKS YOU: FIRE HIGH, BACK SLOW, NEVER RUN DOWNHILL. IF IT MUST BE KILLED, KILL IT WELL AND QUICKLY.\n\nAND THEN DO WHAT I DO, THOUGH NONE OF MY APPRENTICES UNDERSTAND IT. STAND OVER IT A MOMENT. SAY: YOU WERE A GOOD WOLF ONCE, AND NONE OF THIS WAS YOUR IDEA. IT CHANGES NOTHING. SAY IT ANYWAY.", teaches: None },
    Book { id: "foliodead", title: "FOLIO: THE RESTLESS DEAD", cat: "FIELD NOTES", by: "WARDEN ILSE", where_: "dungeon", col: 0x5a8a4a, text: "FIRST, WHAT THEY ARE NOT. THEY ARE NOT HUNGRY. THEY ARE NOT VENGEFUL. THEY ARE NOT YOUR GRANDFATHER, WHATEVER THE FACE SUGGESTS - AND IT WILL SUGGEST, AND YOU MUST NOT LISTEN.\n\nTHE RISEN REMEMBER SHAPES, NOT NAMES. A DOOR MEANS GO THROUGH. A FENCE MEANS FOLLOW. A LIT WINDOW MEANS HOME, AND THAT ONE IS THE SORROW AND THE DANGER BOTH, BECAUSE THEY WILL WALK TO A LIT WINDOW ALL NIGHT, PATIENT AS RAIN, AND A FRIGHTENED HOUSEHOLDER WITH AN AXE MAKES EVERYTHING WORSE.\n\nDROP THEM WITH IRON OR FLAME AND THEY DO NOT COMPLAIN. THAT IS THE WORST OF IT. A BEAST FIGHTS FOR ITS LIFE. THE RISEN JUST STOP, ALMOST GRATEFULLY, LIKE A MAN PUT AT LAST INTO A CHAIR.\n\nTHE LANTERN FOLK SPEAK THE NAMES EACH WINTER SO THE NAMES STAY WITH THE LIVING, WHERE THEY ARE SAFE. WHEN I PUT ONE DOWN I TELL IT: YOUR NAME IS KEPT. WALK EASY. I DO NOT KNOW IF IT HELPS THEM. I KNOW IT HELPS ME.", teaches: None },
    Book { id: "foliowisp", title: "FOLIO: WISPS, AND WHY YOU MUST NOT", cat: "FIELD NOTES", by: "WARDEN ILSE", where_: "camp", col: 0x5a8a4a, text: "A WISP IS NOT A BEAST. IT HAS NO BODY, NO HUNGER, NO DEN. I INCLUDE IT IN THE FOLIO BECAUSE IT KILLS MORE TRAVELLERS THAN BEARS DO, AND KILLS THEM GENTLY.\n\nWHAT IT IS, TRULY, NO ONE KNOWS. THE COLLEGE SAYS: A KNOT IN THE LEAK, A CANDLE-SIZED FLAW WHERE POWER PUDDLES. THE GRAVEFOLK SAY: A SOUL THAT MISSED ITS TURNING. MY GRANDMOTHER SAID: A WANT, WEARING A LIGHT. I HAVE FOUND NO REASON TO IMPROVE ON MY GRANDMOTHER.\n\nIT BOBS. IT WAITS. IT MOVES OFF THE PATH EXACTLY AS FAST AS YOU FOLLOW - NEVER FASTER. IT DOES NOT LURE YOU TO A CLIFF OR A BOG, NOTHING SO HONEST. IT SIMPLY LEADS, UNTIL YOU ARE SOMEWHERE NO PATH REMEMBERS, AND THEN IT GOES OUT.\n\nTHE RULE IS ONE WORD LONG. DONT. TEACH IT TO YOUR CHILDREN BEFORE YOU TEACH THEM THEIR LETTERS.", teaches: None },
    Book { id: "lanterncat", title: "THE LANTERN CATECHISM", cat: "SCRIPTURE", by: "THE LANTERN ORDER", where_: "chapel", col: 0xc4c4d4, text: "WHY DO WE LIGHT THE LANTERNS? BECAUSE THE DARK IS LARGE AND A NAME IS SMALL, AND SMALL THINGS ARE LOST WITHOUT A LIGHT TO GATHER BY.\n\nWHY DO WE SPEAK THE NAMES EACH WINTER? BECAUSE THE DEAD FORGET THEMSELVES, AND WE ARE THEIR MEMORY NOW. A NAME SPOKEN ALOUD ONCE A YEAR IS A ROOF KEPT ON A HOUSE NO ONE LIVES IN. THE HOUSE STANDS. THAT IS ALL, AND IT IS ENOUGH.\n\nWHY DO WE GO UNARMED AMONG THE RISEN? BECAUSE THEY WERE FARMERS AND WEAVERS AND MOTHERS, AND YOU DO NOT DRAW STEEL ON A NEIGHBOUR FOR SLEEPWALKING.\n\nWHAT DO WE HOPE? THAT SOMEONE MENDS THE WORLD, AND THE DEAD LIE EASY, AND THE LAST LANTERN CAN BE BLOWN OUT BY SOMEBODY SMILING.\n\nAND UNTIL THEN? UNTIL THEN, WE CARRY OIL.", teaches: None },
    Book { id: "lanternnames", title: "THE BOOK OF KEPT NAMES", cat: "RECORD", by: "THE LANTERN ORDER", where_: "chapel", col: 0x8fa08f, text: "(A LEDGER PAGE, RULED IN A CAREFUL HAND. EACH LINE A NAME, A PLACE, A DATE. A FEW STAND OUT, ANNOTATED.)\n\nHARROW OF THE MILL ROAD. KEPT. HIS WIDOW BRINGS PIE TO THE DIGGER STILL, THOUGH HARROW IS TWELVE WINTERS SPOKEN.\n\nTORWEN, CALLED BOLD. KEPT, THOUGH HE ASKED US NOT TO FUSS. WE SPEAK HIS NAME QUIETLY, AS HE WANTED, AND THE TURNIPS COME UP EVERY YEAR REGARDLESS.\n\nMAREN, ONCE QUEEN. KEPT, THOUGH NO GRAVE HOLDS HER AND NO ONE KNOWS WHERE TO STAND WHEN SPEAKING IT. WE FACE THE BLUEBELLS. IT SEEMED RIGHT.\n\nTHE FORTY-ONE OF EMBERFALL. KEPT, ALL, NEW-WRITTEN THIS VERY YEAR, TO BE SPOKEN IN ONE UNBROKEN BREATH IF THE SPEAKER CAN MANAGE IT.\n\nAND THE ONE OF EMBERFALL WHO WAS NOT FOUND: NAME KEPT, GRAVE EMPTY, LANTERN LIT. WHEREVER YOU ARE - THE ORDER DOES NOT SPEAK YOUR NAME WITH THE DEAD. WE ARE SAVING IT. COME CLAIM IT SOMEDAY, LIVING.", teaches: None },
    Book { id: "seasonsrhyme", title: "THE SEASONS RHYME", cat: "FOLK TALE", by: "SUNG BY CHILDREN", where_: "town", col: 0xd27a9a, text: "SPRING FOR THE SOWING, WET AND NEW, TURNIP AND CARROT AND MORNING DEW. WATER THE ROWS AND MIND THE SKY - THE CLOUDS DO HALF YOUR WORK, SAYS I.\n\nSUMMER FOR TENDING, TALL AND GREEN, TOMATOES RED AND PEPPERS KEEN. THE SUN IS A FRIEND WHO STAYS TOO LONG - DRINK DEEP, WORK EARLY, AND YOU WONT GO WRONG.\n\nFALL FOR THE REAPING, PUMPKIN MOON, CRANBERRY BOGS AND THE HARVEST TUNE. FILL EVERY BASKET AND BARREL AND BIN - WINTER IS PATIENT, BUT SO IS THE GRAIN.\n\nWINTER FOR RESTING, WHITE AND STILL, NOTHING WILL GROW AND NOTHING WILL. MEND YOUR TOOLS BY THE FIRESIDE BRIGHT - SPRING IS A PROMISE. BLOW OUT THE LIGHT.", teaches: None },
    Book { id: "lullabydark", title: "A LULLABY FOR THE DARK", cat: "FOLK TALE", by: "SUNG VERY SOFTLY", where_: "home", col: 0xd27a9a, text: "HUSH NOW, HUSH, THE LAMPS BURN LOW, THERE IS DARK ABOVE AND DARK BELOW. THE DARK BELOW IS OLD AND DEEP - IT KEEPS ITS OWN, SO GO TO SLEEP.\n\nTHE MINERS WALK IT, LAMP IN HAND, THE CRYSTALS GROW WHERE NONE WERE PLANNED, AND UNDER ALL, THE OLD GLYPHS GLEAM - BUT ONLY WHEN YOURE NOT LOOKING, LOVE, SO DREAM.\n\nHUSH NOW, HUSH, DONT MIND THE SOUND, ITS ONLY WATER UNDERGROUND. AND IF IT KNOCKS, IT MEANS NO HARM - THE DEEP JUST TALKS. STAY IN MY ARM.\n\nAND WHEN YOU WAKE, THE SUN WILL CLIMB, THE BREAD WILL RISE, THE BELLS WILL CHIME, AND ALL THE DARK WILL SLEEP INSTEAD. HUSH NOW. HUSH NOW. SLEEPYHEAD.", teaches: None },
    Book { id: "mazesong", title: "THE MAZE SONG", cat: "FOLK TALE", by: "A SKIPPING RHYME", where_: "town", col: 0xd27a9a, text: "(CHILDREN SKIP TO THIS IN EVERY TOWN SQUARE. NOBODY TEACHES IT TO THEM. NOBODY REMEMBERS LEARNING IT.)\n\nLEFT AND LEFT AND ROUND ABOUT, AND DOWN THE BELLS DARK THROAT IS OUT, THE SALT IS WHITE, THE SALT IS DEEP, THE SINGERS SING THE BELL TO SLEEP.\n\nWRONG TURN, WRONG TURN, SAY YOUR PRAYER, EVERY WRONG TURN GETS YOU THERE, COUNT THE TURNS BUT NOT ALOUD - THE MAZE IS LISTENING, SO BE PROUD.\n\nRING THE BELL AND DOWN YOU GO, HOW FAR DOWN? THE SINGERS KNOW. AND IF YOU MEET THEM, SMILE AND SAY: I ONLY CAME TO SKIP AND PLAY.\n\n(SKIP OUT ON THE LAST LINE OR SKIP IT ALL AGAIN. THOSE ARE THE RULES. THE CHILDREN ARE FIRM ON THIS.)", teaches: None },
    Book { id: "notomorrow", title: "THE NO TOMORROW SONG", cat: "FOLK TALE", by: "A DRINKING SONG", where_: "tavern", col: 0xd27a9a, text: "OH THE WORLD BROKE LONG BEFORE MY TIME AND ITLL BE BROKE WHEN IM GONE, SO POUR THE ALE AND STOKE THE FIRE AND HELP ME SING THIS SONG - FOR THE ROADS ALL END IN MONSTERS AND THE MAPS ALL END IN GREY, BUT THE MUGS END HERE, MY DARLING, SO WE DRINK TO NO TOMORROW AND WE LIVE FOR YESTERDAY!\n\nMY GRANDDAD FOUGHT A SHADOWED BEAR AND LOST AN EAR AND WON, MY GRANDMA OUTTALKED A REVENANT TILL IT LAY BACK DOWN AT DAWN - AND NONE OF THEM HAD ANY SENSE AND NEITHER DO I, HOORAY! SO WE DRINK TO NO TOMORROW AND WE LIVE FOR YESTERDAY!\n\n(FINAL VERSE, SUNG STANDING:) AND IF SOME FOOL WITH A SHINING HEAD SHOULD WANDER THROUGH THAT DOOR, WHOS OFF TO MEND THE WRIFTHEART LIKE THE STORIES SAID BEFORE - WELL FILL THEIR CUP AND SEND THEM UP AND CHEER THEM ON THEIR WAY... AND DRINK TO ONE TOMORROW, JUST THE ONE, JUST IN CASE, EH?", teaches: None },
    Book { id: "cookscompanion", title: "THE COOKS COMPANION", cat: "MANUAL", by: "THE INNKEEPERS GUILD", where_: "tavern", col: 0x7a90c0, text: "FIRST LAW OF THE FIRE: FOOD IS NOT PHYSIC. A WOUND WANTS A POTION, NOT A PIE. ANY COOK WHO PROMISES HEALING IN A BOWL IS SELLING YOU SOUP AND THEOLOGY TOGETHER.\n\nWHAT GOOD FOOD DOES IS STEADY YOU. A PROPER ROAST PUTS WARMTH IN THE BLOOD FOR HOURS - THE WELL-FED WALK FARTHER AND KNIT FASTER. A HUNTERS SKEWER PUTS IRON IN THE ARM. A GOOD STEW GUARDS THE GUT AGAINST POISON AND WORSE.\n\nTHE FINE WORK: A PEPPER SAUTE QUICKENS THE STEP. A BERRY PIE SHARPENS THE EYE FOR THE WEAK SPOT. A CRANBERRY TART, FOR REASONS THE GUILD HAS STOPPED INVESTIGATING, MAKES A BODY NOTICEABLY LUCKIER. WE DO NOT ASK. WE BAKE.\n\nEAT BEFORE THE FIGHT, NOT DURING - NOBODY CHEWS WELL WHILE PARRYING. AND MIND THE FIRST LAW ALWAYS: THE BOWL STEADIES, THE BOTTLE MENDS. CONFUSE THEM AND YOUR HEIRS INHERIT EARLY.", teaches: None },
    Book { id: "physician", title: "THE COURT PHYSICIANS NOTES", cat: "RECORD", by: "PHYSICIAN ROYAL", where_: "castle", col: 0x8fa08f, text: "ON THE QUEENS ILLNESS: THE PALE FEVER TAKES WHOM IT TAKES. I HAVE WRITTEN THIS SENTENCE FOR THIRTY YEARS AND IT HAS NEVER ONCE HELPED ANYBODY. SHE ASKED ME PLAINLY HOW LONG. I TOLD HER PLAINLY. SHE THANKED ME, AND SPENT HER LAST STRENGTH ARRANGING THE KINGS COMFORT - WHICH IS THE FEVER FOR YOU. IT TAKES THE BEST FIRST, AND MAKES THEM SPEND THEIR FINAL WEEKS COMFORTING US.\n\nON THE KING, AFTER: I WAS CALLED FOUR TIMES. HE IS NOT ILL. HE SLEEPS AN HOUR A NIGHT, EATS WHAT IS PUT DIRECTLY BEFORE HIM, AND IS COURTEOUS AND FAR AWAY.\n\nI PRESCRIBED REST. THE MAGE PRESCRIBED OTHERWISE - OLD TEXTS, LONG HOURS, HOPE. HOPE IS A MEDICINE, I GRANT. BUT LIKE ANY MEDICINE, DOSAGE IS EVERYTHING, AND SORREL DOES NOT MEASURE.\n\nMY FINAL NOTE IN THIS FILE, AND LET IT STAND AS MY OBJECTION: GRIEF IS NOT A WOUND. IT IS A WEATHER. YOU CANNOT LANCE IT, MAJESTY. YOU CAN ONLY LET IT RAIN.", teaches: None },
    Book { id: "towerforge", title: "INVENTORY: THE EAST TOWER FORGE", cat: "RECORD", by: "CLERK OF THE WORKS", where_: "castle", col: 0x8fa08f, text: "QUARTERLY INVENTORY OF THE COLD FORGE, EAST TOWER, BEING DISUSED THESE FORTY YEARS.\n\nFOUND: ONE ANVIL, RECENTLY DRESSED. CHARCOAL, FRESH, THREE SACKS - NOT REQUISITIONED THROUGH THIS OFFICE. THE GOOD TONGS, MISSING FROM THE ARMOURY SINCE MIDWINTER, HERE. THE FLOOR SWEPT BY SOMEONE WHO DOES NOT SWEEP FOR A LIVING.\n\nFOUND ALSO: FILINGS OF A METAL THIS CLERK DOES NOT KNOW, PALE AS MOONLIGHT AND FAINTLY WARM. SEVEN CRUCIBLES, SIX BROKEN AS IF FROM WITHIN. A BUCKET OF QUENCH-WATER THAT HAS NOT GONE STALE THOUGH IT MUST BE MONTHS OLD, AND WHICH THIS CLERK DID NOT LIKE TO PUT HIS HAND IN, AND DID NOT.\n\nNOTED FOR THE RECORD: WHOEVER WORKS HERE WORKS ALONE, AT NIGHT, AND IS PERMITTED TO, FOR THE GUARD ROTATION OMITS THIS TOWER BY WRITTEN ORDER. THE ORDER BEARS THE ROYAL SEAL.\n\nRECOMMENDATION: NONE. THIS CLERK COUNTS THINGS. THIS CLERK HAS COUNTED THEM.", teaches: None },
    Book { id: "throneroomdoor", title: "THE WATCH-BOOK OF THE THRONE DOOR", cat: "RECORD", by: "THE CASTLE WATCH", where_: "castle", col: 0x8fa08f, text: "(A GUARD ROTATION LOG. THE EARLY PAGES ARE ROUTINE. THE LATER ENTRIES ARE NOT.)\n\nFIRST MONTH. POST QUIET. DOOR SEALED PER ORDER. NOTHING TO REPORT.\n\nTHIRD MONTH. SOUND FROM WITHIN, LOW, LIKE A MAN SPEAKING TO SOMEONE PATIENT. REPORTED. TOLD: THE HALL IS EMPTY. THE HALL HAS BEEN EMPTY SINCE THE NIGHT. NOTED.\n\nFIFTH MONTH. THE WEEPING AGAIN. ANNIS WILL NOT STAND THE MIDNIGHT WATCH ANY MORE AND I HAVE STOPPED MAKING HER. IT IS NOT FEAR, SHE SAYS. IT IS WORSE THAN FEAR. SHE SAYS YOU START WANTING TO OPEN THE DOOR AND COMFORT IT.\n\nSIXTH MONTH. I HAVE MOVED THE POST TEN PACES BACK. THE WEEPING DOES NOT GET QUIETER WITH DISTANCE. NOTED, AND I DID NOT LIKE NOTING IT.\n\nLAST ENTRY. THE WATCH IS DISSOLVED BY ORDER OF NO ONE, BECAUSE THERE IS NO ONE LEFT TO ORDER IT. IF ANY READ THIS: THE DOOR NEEDS NO GUARDING. NOTHING WANTS OUT. THAT IS NOT THE PROBLEM WITH THE DOOR.", teaches: None },
    Book { id: "nobook", title: "A PAGE FROM NO BOOK", cat: "LEGEND", by: "HAND UNKNOWN", where_: "castle", col: 0x9a6ad0, text: "(A SINGLE LOOSE PAGE. THE PAPER MATCHES NO STOCK THE COLLEGE KNOWS. THE INK SITS ON TOP OF THE PAGE, AS IF UNWILLING TO SOAK IN.)\n\nYOU WHO READ: THE HEART WAS A DOOR. THE DOOR WAS A HEART. THESE ARE NOT RIDDLES. THEY ARE THE SAME SENTENCE, SAID FROM EACH SIDE.\n\nON YOUR SIDE, A KNOCKING. ON OURS - NO. THERE IS NO WORD IN YOUR INK FOR WHAT IT IS ON OURS.\n\nTHE ONE WHO STRUCK IT IS HELD IN THE HINGE. HE IS NOT ON YOUR SIDE. HE IS NOT ON OURS. HE IS IN THE BETWEEN, WITH THE BEAT HE STOLE, AND HE CANNOT PUT IT DOWN, AND HE CANNOT STOP HEARING IT.\n\nWE DO NOT HATE YOU. A SHORE DOES NOT HATE THE OTHER SHORE.\n\nBRING THE TEN PIECES. OPEN NOTHING. MEND. AND DO NOT LOOK LONG AT THE FAR SIDE, LITTLE SHORE, HOWEVER SWEETLY IT ASKS. IT HAS BEEN ALONE A LONG TIME, AND IT HAS FORGOTTEN ITS MANNERS.", teaches: None },
    Book { id: "firsttown", title: "THE TALE OF THE FIRST TOWN", cat: "LEGEND", by: "TOLD BY EVERYONE", where_: "town", col: 0x9a6ad0, text: "AFTER THE BREAKING, THE FOLK RAN. THAT PART EVERY TELLER TELLS THE SAME. THEY RAN UNTIL THE LAND STOPPED SHAKING, AND THEN THEY KEPT RUNNING, BECAUSE STOPPING HAD STOPPED OCCURRING TO THEM.\n\nUNTIL ONE EVENING AN OLD WOMAN SAT DOWN ON A FLAT ROCK AND SAID: HERE.\n\nHERE WHAT, THEY ASKED. HERE, SHE SAID, AND PUT A CANDLE ON THE ROCK, AND LIT IT.\n\nAND BECAUSE ONE LIGHT WAS LIT, ANOTHER FELT SAFE TO STOP BESIDE IT. AND ANOTHER BESIDE THAT. AND BY SPRING THERE WAS A WELL, AND BY FALL A WALL, AND BY THE NEXT YEAR THE RUNNING WAS SOMETHING THAT HAD HAPPENED TO THEM, INSTEAD OF SOMETHING THEY WERE.\n\nTHE TOWN IS NOT NAMED IN THE TALE. EVERY TOWN SAYS IT WAS THEM. EVERY TOWN IS RIGHT. THAT IS HOW THE TALE WORKS, AND WHY WE KEEP THE LAMP IN THE WINDOW LIT.", teaches: None },
    Book { id: "saltwives", title: "THE SALT-WIVES TALE", cat: "LEGEND", by: "TOLD IN THE WASTES", where_: "camp", col: 0x9a6ad0, text: "THE WOMEN WHO RAKE SALT AT THE EDGE OF THE WASTES WILL TELL YOU, IF YOU HELP WITH THE RAKING AND DO NOT ASK STUPID QUESTIONS, ABOUT THE SINGING.\n\nIT COMES UP THROUGH THE CRUST ON STILL DAYS. NOT WORDS - THE SHAPE WHERE WORDS WOULD GO. THE OLD WIVES SAY THE SALT CARRIES SOUND THE WAY WATER CARRIES LIGHT: BENT, AND FROM FARTHER DOWN THAN YOU THINK.\n\nTHEY LEAVE A CUP OF WELL-WATER ON THE CRUST AT MIDSUMMER. FOR THE THIRSTY BELOW, THEY SAY. BY MORNING IT IS ALWAYS EMPTY. EVAPORATION, SAYS THE COLLEGE. THE SALT-WIVES HAVE HEARD OF EVAPORATION. THEY LEAVE THE CUP.\n\nAND THIS THEY TEACH THEIR DAUGHTERS: IF THE SINGING EVER TURNS GLAD - PACK. GLAD MEANS THEY HAVE SOMETHING TO BE GLAD ABOUT, AND NOTHING GOOD HAS EVER BEEN CARRIED UP OUT OF THAT DARK.", teaches: None },
    Book { id: "kingwholistened", title: "THE KING WHO LISTENED", cat: "FOLK TALE", by: "A FIRESIDE FABLE", where_: "town", col: 0xd27a9a, text: "ONCE THERE WAS A KING WHO LOVED A QUEEN, AND THE QUEEN DIED, AS QUEENS AND MILLERS WIVES ALIKE WILL DO.\n\nAND GRIEF CAME TO SIT WITH THE KING, AS IT SITS WITH EVERYONE, AND IF HE HAD LET IT SIT, IT WOULD IN TIME HAVE STOOD, TIPPED ITS HAT, AND GONE. THAT IS ALL GRIEF EVER ASKS: A CHAIR, AND TIME.\n\nBUT A CLEVER VOICE CAME TO THE KING AND SAID: WHY SUFFER? THE DOOR SHE WENT THROUGH IS ONLY LOCKED. AND THE KING, BEING POWERFUL, WHICH IS A KIND OF HUNGER, AND CLEVER, WHICH IS A KIND OF DEAF, LISTENED.\n\nCHILDREN, YOU KNOW THE SOUND THE STORY MAKES NEXT. YOU HAVE HEARD IT IN THE THUNDER.\n\nSO WHEN YOUR OWN CLEVER VOICE COMES - AND IT WILL, IT COMES TO EVERYONE, WEARING YOUR OWN GRIEF FOR A COAT - GIVE IT NO CHAIR. GRIEF GETS THE CHAIR. THE VOICE GETS THE DOOR. THE SHUT ONE.", teaches: None },
    Book { id: "beforeheart", title: "FRAGMENT: BEFORE THE HEART", cat: "LEGEND", by: "TRANSLATED FROM STONE", where_: "dungeon", col: 0x9a6ad0, text: "(COPIED FROM CARVINGS IN THE STARLESS DEEP, IN THE DEEP-FOLK GLYPHS THAT GLOW WHEN YOU LOOK AWAY. THE TRANSLATION IS THE COLLEGES BEST GUESS, AND THE COLLEGE DOES NOT GUARANTEE IT.)\n\nBEFORE THE HEART, THE (UNTRANSLATED), AND THE WORLD WAS NOT ONE, BUT MANY, AS BEADS BEFORE THE STRING.\n\nTHEN CAME THE STRINGING. WHO STRUNG? (THE GLYPH HERE IS THE ONE THE DEEP-FOLK USED FOR BOTH GARDENER AND BUTCHER.)\n\nAND THE BEATING BEGAN, AND THE MANY WERE HELD AS ONE. AND WE WENT DOWN BENEATH THE BEATING, FOR WE REMEMBERED THE QUIET, AND MISSED IT.\n\n(THE REMAINING GLYPHS ARE UNTRANSLATED. THE FINAL LINE REPEATS ONE GLYPH ELEVEN TIMES. THE COLLEGES BEST GUESS FOR IT IS: LISTEN. THE COLLEGES SECOND GUESS IS: HIDE. THE COLLEGE NOTES, IN A FOOTNOTE IT DECLINED TO SIGN, THAT IN DEEP-FOLK THESE MAY BE THE SAME WORD.)", teaches: None },
    Book { id: "landgreenmaw", title: "THE LANDS: THE GREENMAW", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "THE JUNGLE SOUTH OF THE HEARTLANDS IS CALLED THE GREENMAW, AND UNLIKE MOST NAMES ON THE OLD MAPS, THIS ONE IS NOT POETRY. IT IS A WARNING WITH A SPELLING.\n\nTHE GREEN HERE DOES NOT GROW SO MUCH AS ADVANCE. THE SURVEY CUT A CAMP ON MONDAY AND RECUT IT ON WEDNESDAY. THE ROAD THE OLD MAPS PROMISE IS DOWN THERE SOMEWHERE, DIGESTING.\n\nEVERYTHING IS LOUD, WET, AND ALIVE, AND MOST OF IT IS EATING MOST OF THE REST OF IT, AMIABLY, THE WAY A MARKET CROWD HAGGLES.\n\nMY COMPLAINTS: THE DAMP GOT INTO MY BOOTS, MY NOTES, AND MY OPINIONS. MY WONDER: A FLOWER THE SIZE OF A CART WHEEL THAT TURNS TO FACE YOU AS YOU PASS. IT WANTS NOTHING, SAYS THE GUIDE. IT IS ONLY CURIOUS. I HAVE MET DUCHESSES WITH WORSE MANNERS.", teaches: None },
    Book { id: "landtarmire", title: "THE LANDS: THE TARMIRE", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "PAST THE HONEST SWAMP LIES THE TARMIRE, WHERE THE WATER GIVES UP AND BECOMES TAR. THE DIFFERENCE MATTERS. A SWAMP WANTS YOUR BOOTS. THE TARMIRE WANTS YOUR SCHEDULE.\n\nEVERYTHING HERE HAPPENS SLOWLY. THE PONDS BLINK. THE BUBBLES TAKE A QUARTER HOUR TO RISE AND ARRIVE WITH A SIGH LIKE AN OLD DOG LYING DOWN. THE TREES LEAN AT ANGLES THAT SUGGEST THEY FELL YEARS AGO AND ARE IN NO HURRY TO LAND.\n\nWADE ONLY WHERE THE REEDS GROW - REEDS ARE HONEST, THEY NEED BOTTOM. WHERE THE SURFACE IS SMOOTH AND PATIENT, GO AROUND. THE MIRE HAS KEPT EVERYTHING IT HAS EVER CAUGHT, PERFECTLY, AND THE SURVEY DECLINES TO LIST WHAT THE LOCALS SAY IT SHOWS THEM ON STILL EVENINGS.\n\nMY COMPLAINT IS SINGULAR: THE SMELL. THE ARCHIVE HAS NOT ALLOTTED SUFFICIENT PAGES.", teaches: None },
    Book { id: "landstormreach", title: "THE LANDS: STORMREACH", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "THERE IS A COUNTRY WHERE THE SKYS GRIEF POOLS, THE WAY WATER FINDS A BASIN. IT IS CALLED STORMREACH, AND I HAVE NEVER BEEN ANYWHERE THAT DESERVED ITS NAME MORE THOROUGHLY.\n\nIT IS RAINING IN STORMREACH NOW. I DO NOT NEED TO CHECK. THE THUNDER THERE DOES NOT ROLL AND DEPART - IT PACES, LIKE SOMETHING KEPT IN.\n\nTHE FOLK ON ITS EDGES ARE THE CALMEST PEOPLE I HAVE MET, FOR THE SAME REASON SAILORS ARE CALM. THEY BUILD LOW, ROOF STEEP, AND SPEAK OF THE STORM AS A NEIGHBOUR: LOUD, GRIEVING, NOT TO BE PROVOKED, GOOD FOR THE CISTERNS.\n\nTHE STORMCORE SLEEPS SOMEWHERE UNDER THOSE PEAKS, AND THE THUNDER IS THE SHARD TALKING IN ITS SLEEP. STAND ON THE HIGH PASSES IN A BREAK BETWEEN CLOUDS AND YOU CAN FEEL THE NEXT PEAL GATHERING IN YOUR TEETH. I RECOMMEND THE EXPERIENCE. ONCE.", teaches: None },
    Book { id: "landgalewind", title: "THE LANDS: THE GALEWIND STEPPE", cat: "FIELD NOTES", by: "GEOGRAPHER MULL", where_: "camp", col: 0x5a8a4a, text: "THE STEPPE IS THE EMPTIEST COUNTRY OF THE SURVEY AND THE HARDEST TO DESCRIBE, BECAUSE ITS ONLY FEATURE IS IN A HURRY.\n\nTHE WIND HERE HAS NOT STOPPED SINCE THE BREAKING. NOT PAUSED, NOT TURNED - STOPPED BEING A THING THAT STOPS. THE GRASS GROWS ALREADY LEANING. THE BIRDS WALK. THE LOCALS BUILD THEIR DOORS ON THE EAST WALL, ALL OF THEM, AND A STRANGER WHO BUILDS OTHERWISE IS WATCHED WITH THE PITY RESERVED FOR THE SOON-TO-BE-EDUCATED.\n\nCONVERSATION OUTDOORS IS CONDUCTED AT A SHOUT, THREE WORDS AT A TIME. THE STEPPE FOLK ARE ACCORDINGLY FAMOUS FOR SAYING NOTHING THEY DO NOT MEAN.\n\nMY WONDER, RECORDED WITH GRIT IN MY TEETH: AT DUSK THE WIND DROPS FOR PERHAPS TEN BREATHS - THE DAYS ONE PAUSE - AND THE WHOLE LAND STANDS UP STRAIGHT. GRASS, BIRDS, FOLK. ALL OF IT UPRIGHT, ALL OF IT SILENT, LIKE THE WORLD REMEMBERING ITSELF. THEN THE WIND RETURNS, AND EVERYONE LEANS BACK INTO THEIR LIVES.", teaches: None },
    Book { id: "fletchingtold", title: "FLETCHING, PLAINLY TOLD", cat: "MANUAL", by: "THE BOWYERS BENCH", where_: "town", col: 0x7a90c0, text: "A BOW IS A SPRING THAT LOVES YOU. TREAT IT SO.\n\nWOOD: STRAIGHT-GRAINED, SEASONED A FULL YEAR. GREEN WOOD MAKES A BOW THE WAY GREEN FOLK MAKE PROMISES - EAGERLY, ONCE.\n\nTHE STRING TEACHES THE ARROW NOTHING. THE ARROW LEARNS EVERYTHING FROM YOUR BREATH. DRAW, SETTLE, LET THE OUT-BREATH LOOSE IT. AN ARROW RELEASED MID-BREATH GOES WHERE YOUR NEXT WORRY IS, NOT WHERE THE MARK IS.\n\nKEEP ARROWS DRY, FLETCHINGS PROUD, AND NEVER LOOSE AT WHAT YOU HAVE NOT NAMED. THE WOODS ARE FULL OF THINGS THAT LOOK LIKE OTHER THINGS, ESPECIALLY IN THE HOLLOWWOOD, ESPECIALLY AT DUSK, AND AN ARROW CANNOT BE APOLOGIZED TO ITS TARGET.\n\nLAST: A SPARE STRING COSTS A COPPER AND WEIGHS NOTHING. THE BOWYER HAS NEVER ONCE SOLD A SECOND STRING TO THE SAME CUSTOMER WITHOUT A STORY ATTACHED, AND THE STORIES ARE NEVER GOOD.", teaches: None },
    Book { id: "homesteader", title: "THE HOMESTEADERS PRIMER", cat: "MANUAL", by: "THE CARPENTERS HALL", where_: "town", col: 0x7a90c0, text: "SO YOU MEAN TO BUILD. GOOD. A HOUSE IS THE ONLY ARGUMENT AGAINST THE DARK THAT THE DARK RESPECTS.\n\nFIRST THE WORKBENCH - EVERYTHING ELSE IS BUILT AT IT, INCLUDING BETTER WORKBENCHES. THEN WALLS: FORTY GOOD TIMBERS, TWENTY-FIVE SOUND STONES, AND MORE FIBER FOR CHINKING THAN YOU THINK. ALWAYS MORE FIBER THAN YOU THINK.\n\nSITE IT BY WATER BUT NOT ON IT. NEAR A ROAD BUT NOT ASTRIDE IT. AND NEVER, WHATEVER THE VIEW, ON THE PRETTY RISE WHERE THE GRASS GROWS IN A PERFECT RING. THE HALL DECLINES TO EXPLAIN THIS RULE. THE HALL HAD A CHAPTER HOUSE ON SUCH A RISE, ONCE.\n\nINSIDE: BED FIRST, HEARTH SECOND, TABLE THIRD, CHEST FOURTH. A CRAFTSMAN WILL TELL YOU A DIFFERENT ORDER. THE CRAFTSMAN HAS NOT SLEPT ON HIS FLOOR LATELY.\n\nAND WHEN THE ROOF CLOSES OVER YOU THE FIRST NIGHT, AND THE RAIN COMES, AND YOU LIE THERE LISTENING TO IT MISS YOU - THAT SOUND IS THE WHOLE TRADE, FRIEND. EVERYTHING ELSE IS JOINERY.", teaches: None },
    Book { id: "rainrows", title: "RAIN FOR THE ROWS", cat: "FOLK TALE", by: "A WANDERING BARD", where_: "tavern", col: 0xd27a9a, text: "A FARMER IN THE DRY YEAR PAID ME MY SUPPER TO PLAY HER ROWS SOMETHING SAD, FOR SHE SAID THE SKY ONLY WEEPS WHEN IT IS MOVED. I PLAYED, AND IT WEPT, AND THE BEANS CAME UP. MAKE OF THAT WHAT YOU LIKE.\n\nTHE FLUTE HAS FOUR VOICES, IF NO ONE HAS SHOWN YOU: ONE FOR EACH WAY THE WIND BLOWS. LOW UNDER YOUR THUMB IN THE SOUTH, HIGH ABOVE ALL IN THE NORTH, AND THE TWO MIDDLE WINDS EAST AND WEST.\n\nTHE RAIN SONG, THEN, AS SHE TAUGHT IT AND I STOLE IT: DOWN - UP, DOWN - UP. LIKE A BUCKET DROPPED TWICE DOWN A WELL, AND TWICE HAULED BACK FULL.\n\nPLAY IT UNDER AN OPEN SKY AND THE CLOUDS COME CURIOUS. PLAY IT IN A STORM AND THEY LOSE INTEREST AND WANDER OFF. EITHER WAY THE BEANS ARE WATERED OR THE WASHING DRIES, AND SOMEBODY OWES YOU SUPPER.", teaches: Some("stormcall") },
    Book { id: "morningmaker", title: "THE MORNINGMAKER", cat: "SCRIPTURE", by: "ORDER OF THE DAWN", where_: "chapel", col: 0xc4c4d4, text: "BEFORE THE SUNDERING THE SUN KEPT ITS OWN COUNSEL AND NO SONG COULD HURRY IT. NOW THE SKY IS CRACKED LIKE EVERYTHING ELSE, AND THROUGH THE CRACKS A TUNE CAN REACH IT.\n\nTHE ORDER RISES SINGING AND SETS SINGING. THE HYMN IS SHORT, FOR THE SUN HAS NO PATIENCE FOR VERSES: RIGHT, THEN UP, THEN LEFT, THEN DOWN. OUT OF THE EAST, UP TO THE NOON, WEST, AND DOWN TO REST - THE SUNS WHOLE ROAD IN FOUR NOTES.\n\nSUNG IN DARKNESS IT FETCHES THE MORNING. SUNG IN DAYLIGHT IT PULLS THE EVENING UP OVER THE WORLD LIKE A BLANKET, FOR REST IS ALSO HOLY.\n\nUSE IT SPARINGLY, PILGRIM. THE DAYS YOU SKIP ARE STILL YOURS TO ANSWER FOR.", teaches: Some("sunsong") },
    Book { id: "stonesthatsing", title: "THE STONES THAT SING", cat: "LEGEND", by: "UNKNOWN", where_: "camp", col: 0x9a6ad0, text: "YOU HAVE SEEN THEM AND WALKED PAST: TALL CARVED STONES ALONE IN THE WILD, FOUR MARKS ON THE FACE, GLOWING FAINT AS BANKED COALS. THE OLD FOLK CALLED THEM DOOR-STONES AND LEFT THEM BE.\n\nTHEY ARE DOORS. THE DEEP-FOLK SEALED THEIR ROADS UNDER SONG INSTEAD OF LOCK AND KEY, FOR A KEY CAN BE STOLEN BUT A SONG MUST BE GIVEN.\n\nTHIS IS THE GIVING: LEFT - RIGHT, LEFT - RIGHT. WEST AND EAST, TWICE OVER, LIKE KNOCKING ON A NEIGHBORS SHUTTER.\n\nSTAND NEAR AND PLAY, AND THE STONE WILL REMEMBER IT IS A DOOR. WHAT WAITS BELOW IS ANOTHER MATTER. THE DEEP-FOLK SEALED THEIR ROADS FOR REASONS, AND NOT ALL THE REASONS DIED.", teaches: Some("opening") },
    Book { id: "bellcanticle", title: "THE BELL CANTICLE", cat: "SCRIPTURE", by: "THE SHARDED CHOIR", where_: "dungeon", col: 0xc4c4d4, text: "THE CHOIR SINGS THE MAZE AND THE MAZE IS SUNG. UP, THEN LEFT, THEN RIGHT, THEN DOWN THE BELLS DARK THROAT - THE WALK AND THE HYMN ARE ONE, AND BOTH BELONG TO US.\n\nFOR THE FLUTE-HANDED HERETIC WHO STEALS THIS PAGE, TAKE THE NOTES AND CHOKE ON THEM: UP, LEFT, RIGHT, DOWN. FOUR STEPS, AS THE SANCTUM IS WALKED.\n\nPLAYED TRUE, THE AIR ITSELF BECOMES THE BELL. IT TOLLS FROM THE PLAYER OUTWARD AND EVERYTHING UNGODLY IS THROWN BACK ON ITS HEELS - WHICH IS TO SAY, EVERYTHING.\n\nWE WROTE THIS DOWN BECAUSE THE BELL ASKED US TO. THE BELL ASKS FOR STRANGE THINGS LATELY. SING ANYWAY.", teaches: Some("canticle") },
    Book { id: "wardsongbook", title: "THE KINGSGUARD WARD", cat: "SCRIPTURE", by: "DRILLMASTER HOLT", where_: "castle", col: 0xc4c4d4, text: "EVERY RECRUIT LEARNED THE WARD BEFORE THEY WERE TRUSTED WITH AN EDGE. YOU CANNOT SWING WELL IF YOU FLINCH, AND YOU WILL NOT FLINCH IF THE WARD IS IN YOUR EARS.\n\nFOUR NOTES, AND ALL OF THEM ARE THE MIDDLE WINDS - NO HIGH BOAST, NO LOW FEAR: LEFT - RIGHT, RIGHT - LEFT. THE SHIELD ARM CROSSES OVER AND CROSSES BACK, AND THE HUM SITS ON YOU LIKE MAIL.\n\nWHILE IT RINGS, THE BLOWS THAT LAND LAND SOFTER. IT WILL NOT MAKE YOU DEATHLESS. IT MAKES YOU STEADY, WHICH IN MY LONG EXPERIENCE KEEPS MORE MEN ALIVE THAN COURAGE EVER DID.\n\nPLAY IT WITH THE ENEMY ALREADY UPON YOU IF YOU MUST - THE SONG DOES NOT WAIT FOR SAFETY, AND NEITHER, LAD, DOES THE WAR.", teaches: Some("wardsong") },
    Book { id: "lullabybook", title: "THE CRADLE AND THE DARK", cat: "FOLK TALE", by: "A NURSE'S RHYME", where_: "town", col: 0xd27a9a, text: "HUSH NOW. EVERY GOODWIFE IN THE TOWNS KNOWS THE CRADLE-SONG, THOUGH FEW KNOW IT WILL CLOSE THE EYES OF THINGS THAT HAVE NO BUSINESS SLEEPING.\n\nIT FALLS THE WAY A CHILD FALLS INTO SLEEP - FROM HIGH DOWN TO LOW, NEVER CLIMBING BACK: UP, RIGHT, LEFT, DOWN. START AT THE TOP NOTE AND LET IT SINK, STEP BY STEP, INTO THE DARK UNDER YOUR THUMB.\n\nWHATEVER STANDS CLOSE ENOUGH TO HEAR IT NODS AND LIES DOWN. BUT SLEEP IS A THIN BLANKET - STRIKE A SLEEPER AND IT WAKES AT ONCE, SNARLING, SO SING TO BUY A BREATH, NOT A BATTLE.\n\nI SANG IT ONCE TO A WOLF AT THE DOOR. THE WOLF SLEPT. I DID NOT. THAT IS THE BARGAIN.", teaches: Some("lullaby") },
    Book { id: "greensongbook", title: "THE FIELD-WAKING", cat: "ALMANAC", by: "THE WILDFOLK OF THE FENS", where_: "camp", col: 0xcaa84a, text: "THE SETTLED FOLK WAIT ON THE SEASONS. WE DO NOT WAIT. A CAMP THAT MOVES CANNOT WAIT NINETY DAYS FOR A TURNIP, SO WE SING THEM UP.\n\nTHE TUNE CLIMBS THE WAY A GREEN THING CLIMBS OUT OF THE DIRT - FROM THE LOW NOTE UPWARD: DOWN, LEFT, RIGHT, UP. BEGIN UNDER YOUR THUMB IN THE EARTH AND RISE, NOTE BY NOTE, INTO THE SUN.\n\nSTAND AMONG WHAT YOU HAVE PLANTED AND PLAY, AND WHAT IS SOWN THERE COMES RIPE AT ONCE, AS THOUGH A WHOLE SUMMER PASSED IN A BREATH.\n\nIT ASKS NOTHING OF WHAT DOES NOT GROW - SING IT ON BARE STONE AND IT ONLY MAKES YOU LOOK A FOOL. SING IT ON YOUR ROWS AND EAT WELL.", teaches: Some("greensong") },
];

pub fn get(id: &str) -> Option<&'static Book> {
    BOOKS.iter().find(|b| b.id == id)
}

/// js BOOK_PLACES: which `where_` pools a location draws from.
fn place_pool(place: &str) -> &'static [&'static str] {
    match place {
        "library" => &["town", "home", "tavern", "chapel"],
        "town" => &["town"],
        "home" => &["home", "town"],
        "tavern" => &["tavern", "town"],
        "chapel" => &["chapel", "town"],
        "camp" => &["camp", "town", "dungeon"],
        "dungeon" => &["dungeon", "camp"],
        "castle" => &["castle", "dungeon"],
        _ => &[],
    }
}

/// js bookIdFor: a deterministic pick from the place's pool (the whole shelf if empty).
pub fn book_id_for(place: &str, h: u32) -> &'static str {
    let ok = place_pool(place);
    let pool: Vec<&Book> = if ok.is_empty() {
        BOOKS.iter().collect()
    } else {
        let filtered: Vec<&Book> = BOOKS.iter().filter(|b| ok.contains(&b.where_)).collect();
        if filtered.is_empty() { BOOKS.iter().collect() } else { filtered }
    };
    pool[h as usize % pool.len()].id
}
